import type { Question } from "./questions";

export const PHARMA_PATH_MICRO_QUESTIONS: Question[] = [
  // ── PHARMACOLOGY (IDs 6001–6050) ────────────────────────────────────────────

  // Autonomic pharmacology
  { id:6001, subject:"Pharmacology", stem:"Atropine produces mydriasis (pupil dilation) by blocking which receptor?", options:["Nicotinic N1 receptor","Muscarinic M3 receptor on iris sphincter","Alpha-1 adrenoceptor on iris dilator","Beta-2 adrenoceptor on ciliary muscle"], answer:1, explanation:"Atropine blocks muscarinic M3 receptors. In the eye it blocks M3 on the iris sphincter pupillae (causing mydriasis) and M3 on the ciliary muscle (causing cycloplegia/loss of accommodation). It does NOT block nicotinic or adrenergic receptors at therapeutic doses." },
  { id:6002, subject:"Pharmacology", stem:"A patient presents with excessive salivation, lacrimation, urination, diarrhoea, GI cramps, emesis, bradycardia, and miosis after working in a field sprayed with pesticide. The first drug to administer is:", options:["Pralidoxime","Atropine","Neostigmine","Physostigmine"], answer:1, explanation:"This is organophosphate poisoning presenting with SLUDGE syndrome (Salivation, Lacrimation, Urination, Defecation, GI cramps, Emesis) due to AChE inhibition → excess ACh. Atropine (muscarinic blocker) is given FIRST to reverse muscarinic effects. Pralidoxime reactivates AChE but must be given early (before 'aging') and after atropine." },
  { id:6003, subject:"Pharmacology", stem:"Pralidoxime (2-PAM) is used in organophosphate poisoning. Its mechanism of action is:", options:["Competitively blocks muscarinic receptors","Reactivates acetylcholinesterase by cleaving the phosphate bond","Inhibits phosphodiesterase to reduce ACh accumulation","Directly blocks nicotinic receptors at NMJ"], answer:1, explanation:"Pralidoxime is an oxime that cleaves the phosphorylated AChE bond, regenerating active enzyme — this reverses both muscarinic AND nicotinic/CNS effects. It must be given within hours before 'aging' (irreversible phosphorylation) occurs. Atropine only handles muscarinic effects." },
  { id:6004, subject:"Pharmacology", stem:"Neostigmine is used to reverse non-depolarising neuromuscular blockade at the end of surgery. Its mechanism is:", options:["Direct nicotinic agonist","Reversible inhibitor of acetylcholinesterase","Irreversible inhibitor of acetylcholinesterase","Competitive antagonist of atracurium at nicotinic receptor"], answer:1, explanation:"Neostigmine reversibly inhibits AChE (quaternary compound, does not cross BBB), increasing ACh at the NMJ to compete with and displace non-depolarising NMBs. It is always co-administered with glycopyrrolate or atropine to block muscarinic side-effects (bradycardia, bronchospasm). It is also used in myasthenia gravis." },
  { id:6005, subject:"Pharmacology", stem:"Propranolol is contraindicated in bronchial asthma because:", options:["It blocks alpha-1 receptors causing bronchoconstriction","It blocks beta-2 receptors in bronchi causing bronchoconstriction","It increases histamine release from mast cells","It inhibits prostaglandin synthesis"], answer:1, explanation:"Propranolol is a non-selective beta-blocker (beta-1 + beta-2). Beta-2 receptors in bronchial smooth muscle mediate bronchodilation; blocking them causes bronchoconstriction and can precipitate severe asthma attacks. Cardioselective beta-1 blockers (atenolol, metoprolol) are relatively safer but still used with caution in asthma." },
  { id:6006, subject:"Pharmacology", stem:"Drug of choice (DOC) for absence (petit mal) seizures is:", options:["Carbamazepine","Phenytoin","Ethosuximide","Valproate"], answer:2, explanation:"Ethosuximide is the DOC for pure absence seizures. It blocks T-type calcium channels in thalamic neurons, interrupting the 3 Hz spike-and-wave oscillation characteristic of absence seizures. It has no effect on other seizure types. Valproate is preferred if absence coexists with other seizure types." },
  { id:6007, subject:"Pharmacology", stem:"Carbamazepine is the drug of choice for simple and complex partial seizures. Its mechanism of action is:", options:["Enhances GABA activity at GABA-A receptors","Blocks T-type calcium channels","Blocks voltage-gated sodium channels in a use-dependent manner","Inhibits glutamate NMDA receptors"], answer:2, explanation:"Carbamazepine blocks voltage-gated Na+ channels in a use-dependent (frequency-dependent) manner — it preferentially stabilises the inactivated state of Na+ channels, reducing high-frequency neuronal firing. It is DOC for partial seizures and also used in trigeminal neuralgia and bipolar disorder. It is an enzyme inducer (CYP3A4)." },
  { id:6008, subject:"Pharmacology", stem:"Phenytoin demonstrates zero-order (saturation) kinetics at therapeutic doses. The clinical implication of this is:", options:["Linear relationship between dose and plasma level","Small dose increments can cause disproportionately large rise in plasma levels and toxicity","Half-life decreases as dose increases","It is safely excreted unchanged in urine"], answer:1, explanation:"Phenytoin's hepatic hydroxylation enzyme saturates within the therapeutic range, converting first-order to zero-order kinetics. Once saturated, any small dose increase causes a disproportionate and unpredictable rise in plasma levels, precipitating toxicity (nystagmus → ataxia → mental clouding). This mandates careful titration and plasma level monitoring." },
  { id:6009, subject:"Pharmacology", stem:"A 25-year-old woman on phenytoin for epilepsy is noted to have gingival hyperplasia and hirsutism. These are:", options:["Signs of phenytoin toxicity requiring dose reduction","Dose-independent side effects of phenytoin","Allergic reactions requiring drug discontinuation","Signs of phenytoin deficiency"], answer:1, explanation:"Gingival hyperplasia (gum overgrowth due to reduced collagen degradation) and hirsutism (androgen-like effect) are dose-independent (idiosyncratic/chronic) side-effects of phenytoin unrelated to plasma level. Other dose-independent effects: fetal hydantoin syndrome (teratogen - cleft palate, digital hypoplasia), Stevens-Johnson syndrome, lupus-like syndrome, megaloblastic anaemia." },
  { id:6010, subject:"Pharmacology", stem:"Valproate (valproic acid) is the drug of choice for juvenile myoclonic epilepsy (JME). Which of the following is a potentially fatal adverse effect of valproate?", options:["Gingival hyperplasia","Optic neuritis","Hepatotoxicity (fatal hepatic failure, especially in children <2 years on polytherapy)","Peripheral neuropathy"], answer:2, explanation:"Valproate's most serious adverse effect is idiosyncratic fatal hepatotoxicity, especially in children under 2 years receiving polytherapy. Other important side effects: neural tube defects (teratogen - folic acid supplementation crucial), weight gain, hair loss, thrombocytopenia, hyperammonaemia (may cause encephalopathy), PCOS. It is an enzyme inhibitor (increases other drug levels)." },
  { id:6011, subject:"Pharmacology", stem:"Lamotrigine's most serious adverse effect that requires slow titration of the drug is:", options:["Agranulocytosis","Stevens-Johnson syndrome (SJS)/toxic epidermal necrolysis","Pancreatitis","Pulmonary fibrosis"], answer:1, explanation:"Lamotrigine can cause SJS/TEN (severe mucocutaneous reactions), especially if dose is escalated too rapidly or co-administered with valproate (which inhibits lamotrigine metabolism, doubling its levels). Therefore, the titration schedule must be halved when used with valproate. Lamotrigine is relatively safer in pregnancy compared to other antiepileptics." },
  { id:6012, subject:"Pharmacology", stem:"Which antiepileptic drug has the least number of drug-drug interactions and is preferred in elderly patients on multiple medications?", options:["Carbamazepine","Phenytoin","Valproate","Levetiracetam"], answer:3, explanation:"Levetiracetam (LEV) binds synaptic vesicle protein SV2A to modulate neurotransmitter release. It is NOT a substrate, inducer, or inhibitor of CYP450 enzymes and is primarily renally excreted unchanged. This makes it an excellent choice in the elderly or those on multiple medications. It can cause mood changes/irritability as a notable CNS side effect." },
  { id:6013, subject:"Pharmacology", stem:"Haloperidol causes extrapyramidal side effects (EPS). The correct sequence from earliest to latest onset of EPS is:", options:["Tardive dyskinesia → Akathisia → Parkinsonism → Acute dystonia","Acute dystonia → Parkinsonism → Akathisia → Tardive dyskinesia","Akathisia → Acute dystonia → Parkinsonism → Tardive dyskinesia","Parkinsonism → Acute dystonia → Tardive dyskinesia → Akathisia"], answer:1, explanation:"EPS onset sequence: Acute dystonia (hours to days - spasmodic muscle contractions, treat with benztropine/diphenhydramine) → Drug-induced Parkinsonism (weeks - bradykinesia, rigidity, tremor) → Akathisia (weeks - subjective restlessness, treat with propranolol/benzodiazepine) → Tardive dyskinesia (months to years - orofacial choreiform movements, often irreversible, treat by stopping offending drug, clonazepam, clozapine)." },
  { id:6014, subject:"Pharmacology", stem:"Neuroleptic malignant syndrome (NMS) is a potentially fatal reaction to antipsychotic drugs. The four hallmark features are:", options:["Fever + hypotension + diarrhoea + miosis","Hyperthermia + muscular rigidity + autonomic instability + altered consciousness","Seizures + respiratory failure + metabolic acidosis + miosis","Bradycardia + hypothermia + hypotension + coma"], answer:1, explanation:"NMS: Hyperthermia (>38°C) + Lead-pipe muscular rigidity + Autonomic instability (labile BP, tachycardia, diaphoresis) + Altered consciousness. Labs: elevated CK (rhabdomyolysis), leucocytosis, elevated LFTs. Treatment: stop offending drug, supportive care (cooling, hydration), dantrolene (muscle relaxant), bromocriptine (D2 agonist). Mortality 10-20%." },
  { id:6015, subject:"Pharmacology", stem:"Clozapine is the most effective antipsychotic for treatment-resistant schizophrenia and negative symptoms. The major life-threatening adverse effect requiring weekly monitoring is:", options:["Tardive dyskinesia","Agranulocytosis (absolute neutrophil count <500/mm³)","Neuroleptic malignant syndrome","Metabolic syndrome"], answer:1, explanation:"Clozapine causes agranulocytosis in ~1-2% of patients due to immune-mediated destruction of granulocytes, which can be fatal. Mandatory weekly WBC/ANC monitoring for 6 months, then biweekly, then monthly. Drug must be stopped if ANC <1000. Clozapine has lowest EPS risk (no D2 blockade in nigrostriatal pathway) but highest metabolic side effects and seizure risk (dose-dependent)." },
  { id:6016, subject:"Pharmacology", stem:"Olanzapine use is associated with which metabolic complication?", options:["Hyperuricaemia and gout","Metabolic syndrome (weight gain, dyslipidaemia, hyperglycaemia, hypertension)","Peripheral neuropathy","Hypothyroidism"], answer:1, explanation:"Olanzapine has highest risk among atypical antipsychotics for metabolic syndrome: significant weight gain, dyslipidaemia (raised triglycerides), new-onset type 2 diabetes, and hypertension. This is due to H1 (appetite), M3 (insulin resistance), and 5-HT2C (metabolic) blockade. Clozapine and olanzapine have highest metabolic risk; ziprasidone and aripiprazole lowest." },
  { id:6017, subject:"Pharmacology", stem:"Which of the following tricyclic antidepressants (TCA) is most commonly used for nocturnal enuresis in children?", options:["Amitriptyline","Imipramine","Clomipramine","Doxepin"], answer:1, explanation:"Imipramine is used for nocturnal enuresis due to its anticholinergic effect (reduces bladder contractions) and possible antidiuretic hormone release. Amitriptyline is used more for depression, neuropathic pain, and migraine prophylaxis. Clomipramine is DOC for OCD. However, all TCAs are cardiotoxic in overdose (sodium channel blockade → wide complex tachyarrhythmia → treat with IV sodium bicarbonate)." },
  { id:6018, subject:"Pharmacology", stem:"A patient presents with hyperthermia, agitation, myoclonus, hyperreflexia, and diaphoresis after adding linezolid to fluoxetine. This is most likely:", options:["Neuroleptic malignant syndrome","Anticholinergic syndrome","Serotonin syndrome","Malignant hyperthermia"], answer:2, explanation:"Serotonin syndrome occurs with excess serotonergic activity: hyperthermia, agitation, tremor, myoclonus, clonus (especially ankle), hyperreflexia, diaphoresis. Precipitants: SSRI + MAOI, SSRI + linezolid (weak MAOI), SSRI + tramadol/fentanyl/meperidine. Treatment: stop serotonergic drugs, cyproheptadine (5-HT2A antagonist), supportive care (cooling, benzodiazepines for agitation)." },
  { id:6019, subject:"Pharmacology", stem:"The 'cheese reaction' associated with MAOIs occurs because:", options:["MAOIs directly release adrenaline from adrenal medulla","MAOIs block tyramine metabolism in gut/liver, causing tyramine accumulation and noradrenaline release → hypertensive crisis","MAOIs cause increased sensitivity to serotonin in food","MAOIs block dopamine reuptake causing euphoria with fermented foods"], answer:1, explanation:"Tyramine in aged cheese, red wine, and fermented foods normally undergoes first-pass MAO metabolism in gut/liver. MAOIs block this, allowing tyramine to enter circulation, causing massive noradrenaline release from adrenergic nerve terminals → severe hypertensive crisis ('cheese reaction'). Treatment: phentolamine or labetalol. Patients on MAOIs must follow strict tyramine-free diet." },
  { id:6020, subject:"Pharmacology", stem:"Fluoxetine, an SSRI, is considered relatively safe in pregnancy. Which serious neonatal syndrome can occur if taken in the 3rd trimester?", options:["Neonatal withdrawal syndrome (poor feeding, jitteriness, respiratory distress)","Neonatal hypoglycaemia","Neonatal thyroid suppression","Neonatal cholestasis"], answer:0, explanation:"SSRIs taken in the 3rd trimester can cause neonatal adaptation syndrome: irritability, jitteriness, poor feeding, respiratory distress, hypoglycaemia. This is thought to be due to serotonergic overactivity or withdrawal. Despite this, SSRIs (especially sertraline or fluoxetine) are preferred over untreated depression in pregnancy. Paroxetine is associated with cardiac defects (category D)." },
  { id:6021, subject:"Pharmacology", stem:"Vancomycin is associated with 'Red Man Syndrome'. This reaction is:", options:["An IgE-mediated Type I hypersensitivity (true allergy)","A non-immune-mediated infusion reaction due to direct mast cell degranulation, caused by rapid infusion","A Type III immune complex-mediated reaction","A delayed Type IV hypersensitivity reaction"], answer:1, explanation:"Red Man Syndrome is NOT a true allergy. Rapid vancomycin infusion directly (non-immunologically) triggers mast cell degranulation → histamine release → flushing, erythema, pruritus, and urticaria predominantly on face, neck, and upper torso. Treatment: slow the infusion rate to >60 minutes, pre-treat with antihistamines. The drug need not be permanently discontinued." },
  { id:6022, subject:"Pharmacology", stem:"Which aminoglycoside side effect is typically irreversible?", options:["Nephrotoxicity","Ototoxicity (especially cochlear damage causing sensorineural hearing loss)","Neuromuscular blockade","Hypomagnesaemia"], answer:1, explanation:"Aminoglycosides (gentamicin, amikacin, tobramycin) cause: (1) Nephrotoxicity — reversible proximal tubular damage (monitor trough levels, avoid concurrent nephrotoxins); (2) Ototoxicity — often IRREVERSIBLE destruction of cochlear hair cells (high-frequency hearing loss) and vestibular hair cells (vertigo); (3) Neuromuscular blockade (avoid in myasthenia). Streptomycin/gentamicin affect vestibular > cochlear; amikacin/kanamycin affect cochlear > vestibular." },
  { id:6023, subject:"Pharmacology", stem:"Ciprofloxacin's mechanism of action in gram-negative bacteria is:", options:["Inhibits 30S ribosomal subunit","Inhibits cell wall synthesis by binding PBPs","Inhibits DNA gyrase (topoisomerase II) preventing DNA supercoiling","Disrupts cell membrane integrity"], answer:2, explanation:"Fluoroquinolones inhibit DNA gyrase (topoisomerase II) in gram-negative bacteria and topoisomerase IV in gram-positive bacteria, preventing DNA relaxation and replication. Ciprofloxacin has excellent gram-negative coverage. It is avoided in children/pregnancy due to cartilage toxicity (arthropathy in animal studies). Absorption is reduced by divalent cations (Ca²⁺, Mg²⁺, Al³⁺, Fe²⁺) in antacids — chelation." },
  { id:6024, subject:"Pharmacology", stem:"The standard anti-tuberculosis HRZE regimen stands for which drugs?", options:["Hydrazide-Rifampicin-Zinc-Ethambutol","Isoniazid-Rifampicin-Pyrazinamide-Ethambutol","Isoniazid-Rifabutin-Pyrazinamide-Ethionamide","Hydralazine-Rifampicin-Pyrazinamide-Erythromycin"], answer:1, explanation:"HRZE = Isoniazid (H) + Rifampicin (R) + Pyrazinamide (Z) + Ethambutol (E). The intensive phase (2 months: HRZE) is followed by the continuation phase (4 months: HR). Under RNTCP/NIKSHAY in India, weight-based fixed-dose combinations are used. Streptomycin replaces ethambutol in meningeal TB in some protocols. Drug sensitivity testing guides MDR-TB treatment." },
  { id:6025, subject:"Pharmacology", stem:"A patient on isoniazid (INH) for tuberculosis develops tingling and numbness in hands and feet. The best intervention is:", options:["Stop INH immediately","Add pyridoxine (Vitamin B6) 10 mg/day","Add folic acid 5 mg/day","Reduce INH dose by 50%"], answer:1, explanation:"INH causes peripheral neuropathy by depleting pyridoxine (Vitamin B6) — INH competes with pyridoxine-dependent enzymes. All patients on INH should receive prophylactic pyridoxine 10-25 mg/day, especially: malnourished, pregnant women, diabetics, HIV+, alcoholics, elderly. Other INH effects: hepatitis (most serious), lupus-like syndrome, pellagra (niacin deficiency), sideroblastic anaemia." },
  { id:6026, subject:"Pharmacology", stem:"Rifampicin causes orange discolouration of urine, saliva, tears, and sweat. Its more clinically important pharmacological property is:", options:["It is renally excreted and requires dose adjustment in renal failure","It is a potent inducer of CYP450 enzymes (3A4, 2C9, 2C19) reducing levels of many co-administered drugs","It selectively inhibits hepatic metabolism","It blocks P-glycoprotein efflux transporters"], answer:1, explanation:"Rifampicin is a potent CYP450 inducer (especially 3A4, 2C9, 2C19, 1A2) that accelerates metabolism of many drugs: oral contraceptives (contraception failure), warfarin (reduce anticoagulant effect), HIV antiretrovirals, corticosteroids, antifungals, methadone. This is its most clinically important property. Orange discolouration is harmless but patients should be warned. Hepatitis is its most serious adverse effect." },
  { id:6027, subject:"Pharmacology", stem:"Ethambutol's dose-limiting adverse effect that requires monthly monitoring is:", options:["Peripheral neuropathy","Optic neuritis causing red-green colour blindness and reduced visual acuity","Nephrotoxicity","Hyperuricaemia"], answer:1, explanation:"Ethambutol causes optic neuritis (retrobulbar neuritis) manifesting as reduced visual acuity and red-green colour vision impairment. This is dose and duration dependent. Monthly visual acuity and colour vision testing is mandatory. If detected early and drug stopped, it is usually reversible. Ethambutol is contraindicated in children too young to report visual changes and in those with pre-existing optic nerve disease." },
  { id:6028, subject:"Pharmacology", stem:"Pyrazinamide (PZA) is used in the initial 2-month intensive phase of anti-TB therapy. Its most common adverse effect is:", options:["Optic neuritis","Peripheral neuropathy","Hyperuricaemia leading to gout (PZA inhibits uric acid excretion)","Ototoxicity"], answer:2, explanation:"Pyrazinamide causes hyperuricaemia by inhibiting renal tubular secretion of uric acid, leading to gout-like arthralgia (most common side effect). Other effects: hepatotoxicity (most serious), non-gouty arthralgia, flushing. PZA is particularly effective against intracellular (macrophage-residing) dormant TB bacilli due to activity in acidic pH. It has no role in TB meningitis as per some guidelines due to CSF penetration debate." },
  { id:6029, subject:"Pharmacology", stem:"Metformin's primary mechanism of action in type 2 diabetes is:", options:["Stimulates pancreatic beta cells to secrete insulin","Inhibits mitochondrial complex I → AMPK activation → reduces hepatic gluconeogenesis","Blocks alpha-glucosidase to reduce carbohydrate absorption","Stimulates GLP-1 receptors to enhance insulin secretion"], answer:1, explanation:"Metformin inhibits mitochondrial respiratory chain complex I → reduces ATP/AMP ratio → activates AMPK (AMP-activated protein kinase) → decreases hepatic gluconeogenesis (primary effect) and increases peripheral glucose uptake. Key features: NO hypoglycaemia (does not affect insulin secretion), weight neutral/modest weight loss, first-line for T2DM, contraindicated in eGFR <30 mL/min (lactic acidosis risk), hold before contrast media administration." },
  { id:6030, subject:"Pharmacology", stem:"A patient on dapagliflozin (SGLT2 inhibitor) presents with polyuria, polydipsia, but normal blood glucose (euglycaemic DKA). Which of the following is the mechanism?", options:["Peripheral insulin resistance worsened by dapagliflozin","SGLT2 inhibition increases glucagon secretion and ketogenesis even without hyperglycaemia","Direct pancreatic beta cell toxicity","Inhibition of renal glucose reabsorption causing osmotic diuresis and lactic acidosis"], answer:1, explanation:"SGLT2 inhibitors can cause euglycaemic DKA: SGLT2 inhibition reduces insulin secretion and increases glucagon → enhanced lipolysis and ketogenesis → ketoacidosis without marked hyperglycaemia (glucose is lost in urine). Other SGLT2i adverse effects: UTI/genital mycotic infections (due to glycosuria), Fournier's gangrene, volume depletion. Benefits: cardiovascular (reduced HF hospitalisation), renal protection. Stop 3 days before surgery." },
  { id:6031, subject:"Pharmacology", stem:"Semaglutide is a GLP-1 receptor agonist used in type 2 diabetes and obesity. Its most common side effects are:", options:["Hypoglycaemia and weight gain","Nausea and vomiting (gastrointestinal effects)","Peripheral neuropathy and retinopathy","Lactic acidosis and renal failure"], answer:1, explanation:"GLP-1 agonists (semaglutide, liraglutide, exenatide) most commonly cause GI side effects: nausea (very common, dose-limiting), vomiting, diarrhoea, constipation — due to delayed gastric emptying and CNS effects. Other effects: pancreatitis risk (contraindicated in history of pancreatitis), medullary thyroid carcinoma concern (contraindicated in personal/family history). Benefits: significant weight loss, CV benefit (LEADER, SUSTAIN-6 trials), NO hypoglycaemia when used as monotherapy." },
  { id:6032, subject:"Pharmacology", stem:"Which diuretic acts on the thick ascending limb of loop of Henle and is the most potent diuretic?", options:["Hydrochlorothiazide","Spironolactone","Furosemide","Acetazolamide"], answer:2, explanation:"Furosemide (and other loop diuretics: bumetanide, torasemide) inhibit the Na+/K+/2Cl− cotransporter (NKCC2) in the thick ascending limb of loop of Henle, where 25-30% of filtered Na+ is normally reabsorbed. They are the most potent diuretics. Side effects: hypokalaemia, hyponatraemia, metabolic alkalosis, ototoxicity (especially with IV rapid infusion), hyperuricaemia. Used in acute pulmonary oedema, chronic HF, hypertensive emergencies." },
  { id:6033, subject:"Pharmacology", stem:"Which antihypertensive drug is safe in pregnancy and is the drug of choice for hypertension in pregnancy?", options:["ACE inhibitors (enalapril)","ARBs (losartan)","Methyldopa","Beta-blockers (atenolol)"], answer:2, explanation:"Methyldopa (alpha-2 agonist → reduces central sympathetic outflow) is the safest antihypertensive in pregnancy with the most long-term safety data for the foetus. ACEi and ARBs are absolutely contraindicated in pregnancy (teratogenic — renal agenesis, oligohydramnios, skull ossification defects). Labetalol and nifedipine are also used in pregnancy. Hydralazine IV is used for hypertensive emergencies in obstetrics." },
  { id:6034, subject:"Pharmacology", stem:"Heparin overdose causing severe bleeding is treated with:", options:["Vitamin K","Protamine sulphate","Fresh frozen plasma","Tranexamic acid"], answer:1, explanation:"Protamine sulphate reverses heparin by forming a stable ion-pair complex with heparin (protamine is positively charged, heparin is negatively charged). 1 mg protamine neutralises ~100 units of heparin. It partially reverses LMWH (reverses factor Xa inhibition less completely). Vitamin K reverses warfarin. FFP provides clotting factors. Protamine itself can cause anaphylaxis (especially in patients on NPH insulin or with fish allergy)." },
  { id:6035, subject:"Pharmacology", stem:"Warfarin inhibits which enzyme in the clotting factor synthesis pathway?", options:["Thrombin directly","Vitamin K epoxide reductase (VKOR), preventing regeneration of reduced Vitamin K","Factor Xa directly","Protein C activator"], answer:1, explanation:"Warfarin inhibits Vitamin K epoxide reductase complex 1 (VKORC1), which normally recycles Vitamin K epoxide back to active reduced Vitamin K. Without active Vitamin K, gamma-carboxylation of glutamate residues on clotting factors II, VII, IX, X (and anticoagulant proteins C and S) cannot occur, rendering them inactive. Factor VII has shortest half-life (6h), so PT/INR rises first. Full effect in 3-5 days." },
  { id:6036, subject:"Pharmacology", stem:"Morphine's most dangerous acute adverse effect is:", options:["Constipation","Miosis","Respiratory depression (dose-dependent, mediated by mu-opioid receptors in brainstem)","Nausea and vomiting"], answer:2, explanation:"Morphine's most dangerous effect is respiratory depression: mu-opioid receptors in the pre-Bötzinger complex of the brainstem reduce respiratory rate and tidal volume. This is dose-dependent and is the cause of death in opioid overdose (classic triad: pinpoint pupils/miosis, respiratory depression, coma). Reversed by naloxone (competitive mu-opioid antagonist). Constipation (tolerance does NOT develop to this effect) is common chronic side effect." },
  { id:6037, subject:"Pharmacology", stem:"Which NSAID is most selective for COX-2 and thus has least GI toxicity but increased cardiovascular risk?", options:["Aspirin","Ibuprofen","Celecoxib","Indomethacin"], answer:2, explanation:"Celecoxib is a selective COX-2 inhibitor (spares gastric mucosal COX-1 that produces protective prostaglandins → less GI ulcers/bleeding). However, COX-2 inhibition in vascular endothelium reduces prostacyclin (PGI2) without reducing thromboxane A2 (TXA2 is COX-1 from platelets) → prothrombotic state → increased myocardial infarction and stroke risk. Rofecoxib (Vioxx) was withdrawn for this reason. Celecoxib is used in arthritis, FAP." },
  { id:6038, subject:"Pharmacology", stem:"Aspirin in low doses (75-150 mg) is used as antiplatelet therapy. Its mechanism is:", options:["Reversible inhibition of COX-1 in platelets","Irreversible acetylation of COX-1 (and COX-2) permanently inhibiting thromboxane A2 synthesis in platelets","Blockade of ADP P2Y12 receptors on platelets","Inhibition of GPIIb/IIIa receptor"], answer:1, explanation:"Aspirin irreversibly acetylates the serine residue of COX-1 (and at higher doses, COX-2), permanently blocking TXA2 synthesis for the platelet's entire lifespan (~10 days, since platelets lack nuclei and cannot synthesise new COX). This prevents platelet aggregation. Hence aspirin's antiplatelet effect lasts 7-10 days. At high doses, aspirin also inhibits endothelial PGI2 (anti-aggregatory) — so high-dose is not antiplatelet. ADP blockade is the mechanism of clopidogrel." },
  { id:6039, subject:"Pharmacology", stem:"Lignocaine (lidocaine) when used as an antiarrhythmic drug belongs to class:", options:["Class Ia (quinidine-like)","Class Ib (sodium channel blocker, prefers inactivated channels in ischaemic tissue)","Class Ic (flecainide-like)","Class III (potassium channel blocker)"], answer:1, explanation:"Lignocaine is Class Ib antiarrhythmic. It preferentially binds Na+ channels in their inactivated state (which predominates in depolarised/ischaemic tissue), selectively suppressing abnormal automaticity in ventricular cells. It has minimal effect on normal conduction. Used IV for acute ventricular tachycardia/fibrillation (especially peri-MI). Class Ia (quinidine, procainamide) prolong QT; Class Ic (flecainide) dangerous post-MI (CAST trial); Class III (amiodarone, sotalol) prolong APD and QT." },
  { id:6040, subject:"Pharmacology", stem:"Omeprazole (proton pump inhibitor) is a prodrug activated in:", options:["Systemic circulation","Hepatocytes","The acidic canaliculi of parietal cells","Small intestinal enterocytes"], answer:2, explanation:"Omeprazole is a prodrug that is absorbed systemically but selectively concentrated in the acidic secretory canaliculi of parietal cells. In the acidic environment (pH<4), it is converted to the active sulphenamide that irreversibly binds and inhibits H+/K+-ATPase (proton pump). This is why PPIs are most effective when taken 30-60 minutes before meals (when proton pumps are most active). Full effect takes 3-5 days (need to inhibit all pumps)." },
  { id:6041, subject:"Pharmacology", stem:"Succinylcholine is a depolarising neuromuscular blocking agent. What is the expected response to repetitive nerve stimulation?", options:["Fade (progressive decrement in twitch height) on tetanic stimulation","Sustained contraction with tetanic stimulation (no fade)","Post-tetanic potentiation","Complete block with no twitches from the start"], answer:1, explanation:"Succinylcholine (depolarising NMB) causes sustained depolarisation of the motor endplate — this produces fasciculations followed by flaccid paralysis. On tetanic stimulation, there is NO FADE (sustained response) because the block is not competitive. This contrasts with non-depolarising NMBs (vecuronium, atracurium) which show tetanic FADE and post-tetanic potentiation. Succinylcholine is reversed by pseudocholinesterase; prolonged block in pseudocholinesterase deficiency. Risk: hyperkalaemia, malignant hyperthermia." },
  { id:6042, subject:"Pharmacology", stem:"Which opioid analgesic is contraindicated in renal failure due to accumulation of its active metabolite morphine-6-glucuronide?", options:["Fentanyl","Tramadol","Morphine","Buprenorphine"], answer:2, explanation:"Morphine-6-glucuronide (M6G) is an active metabolite of morphine with 20-40× greater analgesic potency and prolonged CNS effects. M6G is renally excreted; in renal failure it accumulates causing respiratory depression and excessive sedation. Fentanyl and methadone are preferred in renal failure. Tramadol (active metabolite also renal-excreted), codeine (morphine conversion) also problematic in renal failure. Buprenorphine is hepatically eliminated — preferred in CKD." },
  { id:6043, subject:"Pharmacology", stem:"Paracetamol (acetaminophen) overdose primarily damages which organ?", options:["Kidneys (acute tubular necrosis)","Liver (centrilobular/zone 3 hepatic necrosis)","Heart (cardiotoxicity)","Lungs (ARDS)"], answer:1, explanation:"Paracetamol overdose causes centrilobular (zone 3) hepatic necrosis. Normal doses: paracetamol is primarily glucuronidated/sulphated; small fraction metabolised by CYP2E1/CYP3A4 to NAPQI (toxic intermediate), neutralised by glutathione. In overdose: GSH depleted → NAPQI binds hepatocyte proteins → necrosis. Treatment: N-acetylcysteine (NAC, replenishes GSH precursor) within 8-10 hours — highly effective. Methionine oral alternative. Risk increased by alcohol (induces CYP2E1, depletes GSH) and malnutrition." },
  { id:6044, subject:"Pharmacology", stem:"Oral contraceptive pills containing oestrogen + progestogen primarily prevent pregnancy through:", options:["Blocking sperm penetration of zona pellucida","Suppressing LH surge and FSH surge → inhibiting ovulation (primary mechanism)","Preventing implantation as primary mechanism","Thickening cervical mucus as primary mechanism"], answer:1, explanation:"Combined OCPs primarily prevent ovulation by negative feedback on the hypothalamo-pituitary axis: oestrogen suppresses FSH (prevents follicular development) and progestogen suppresses LH surge (prevents ovulation). Secondary mechanisms: cervical mucus thickening (impedes sperm), endometrial atrophy (reduces implantation). Risks: VTE (oestrogen increases clotting factors), hypertension, stroke, contraindicated in migraines with aura, liver disease, smokers over 35. Progestogen-only pills (POP/mini-pill) mainly via cervical mucus; suitable for breastfeeding." },
  { id:6045, subject:"Pharmacology", stem:"Digoxin toxicity is potentiated by hypokalaemia. The mechanism is:", options:["Potassium competitively binds to the same site as digoxin on Na+/K+-ATPase; low K+ allows more digoxin binding","Hypokalaemia directly increases digoxin absorption from gut","Hypokalaemia activates vagal tone which competes with digoxin","Low potassium reduces renal digoxin excretion"], answer:0, explanation:"Digoxin inhibits Na+/K+-ATPase by binding to the K+-binding site on the extracellular surface of the pump. Potassium and digoxin compete for this site. Hypokalaemia reduces the competing K+ → more digoxin binding → enhanced toxicity at even normal digoxin levels. This is why loop and thiazide diuretics (which cause hypokalaemia) potentiate digoxin toxicity. Signs of toxicity: nausea/vomiting, visual changes (yellow-green halos), arrhythmias (PAT with block, VT). Treat: digoxin-specific antibody fragments (digoxin Fab/Digibind)." },
  { id:6046, subject:"Pharmacology", stem:"Theophylline's mechanism of bronchodilation in asthma is:", options:["Beta-2 adrenoceptor agonism","Inhibition of phosphodiesterase → increased cAMP → smooth muscle relaxation","Mast cell stabilisation and histamine blockade","Leukotriene receptor antagonism"], answer:1, explanation:"Theophylline (methylxanthine) inhibits phosphodiesterase (PDE) isoenzymes, preventing breakdown of cAMP and cGMP → increased intracellular cAMP → bronchial smooth muscle relaxation. It also antagonises adenosine receptors (bronchoconstrictive) and has anti-inflammatory properties at low doses. Narrow therapeutic index (10-20 mg/L); toxic at >20 mg/L: nausea, seizures, arrhythmias. Many drug interactions (CYP1A2: erythromycin/ciprofloxacin raise levels; rifampicin/smoking lower levels)." },
  { id:6047, subject:"Pharmacology", stem:"Salbutamol (albuterol) is used as a rescue bronchodilator in asthma. It is a:", options:["Non-selective beta agonist","Short-acting selective beta-2 agonist (SABA)","Long-acting selective beta-2 agonist (LABA)","Muscarinic antagonist"], answer:1, explanation:"Salbutamol is a selective beta-2 adrenoceptor agonist with rapid onset (5 min) and short duration (4-6 hours) — hence SABA used for acute rescue. Beta-2 activation in bronchial smooth muscle → Gs protein → adenylyl cyclase → cAMP → PKA → smooth muscle relaxation (bronchodilation). Side effects: tremor, tachycardia, hypokalaemia (at high doses, shifts K+ into cells). LABAs (salmeterol, formoterol) last 12 hours — not for acute rescue, always with ICS." },
  { id:6048, subject:"Pharmacology", stem:"Which immunosuppressant is used to prevent organ transplant rejection and works by inhibiting calcineurin (phosphatase) → blocking IL-2 transcription → T-cell activation inhibition?", options:["Azathioprine","Methotrexate","Cyclosporine","Mycophenolate mofetil"], answer:2, explanation:"Cyclosporine (and tacrolimus) inhibit calcineurin (a phosphatase) by forming complexes with cyclophilin (cyclosporine) or FKBP-12 (tacrolimus). Calcineurin normally dephosphorylates NFAT transcription factor → NFAT nuclear entry → IL-2 gene transcription. Blocking calcineurin prevents IL-2 production → no T-cell proliferation. Key toxicity: nephrotoxicity (reversible if caught early), hypertension, neurotoxicity, gingival hyperplasia (cyclosporine), hirsutism (cyclosporine), alopecia (tacrolimus), post-transplant lymphoma." },
  { id:6049, subject:"Pharmacology", stem:"Sildenafil (used for erectile dysfunction and pulmonary arterial hypertension) works by:", options:["Directly stimulating guanylate cyclase to produce cGMP","Inhibiting phosphodiesterase type 5 (PDE5) → increases cGMP → smooth muscle relaxation and vasodilation","Blocking alpha-1 adrenoceptors in penile vasculature","Acting as a direct nitric oxide donor"], answer:1, explanation:"Sildenafil inhibits PDE5 (the enzyme that degrades cGMP) → cGMP accumulates → activates PKG → smooth muscle relaxation and vasodilation in corpus cavernosum (penile erection) and pulmonary vasculature (for PAH). It is used in PAH to reduce pulmonary vascular resistance. ABSOLUTELY CONTRAINDICATED with nitrates (both increase cGMP/NO pathway → severe hypotension). Also contraindicated in patients with recent MI, stroke, severe cardiac disease." },
  { id:6050, subject:"Pharmacology", stem:"Which antimalarial drug causes haemolytic anaemia in patients with G6PD deficiency?", options:["Chloroquine","Artemether","Primaquine","Lumefantrine"], answer:2, explanation:"Primaquine (and dapsone) cause oxidative haemolysis in G6PD-deficient patients. G6PD catalyses the first step of the pentose phosphate pathway, generating NADPH which maintains glutathione in its reduced (protective) form. G6PD deficiency → insufficient NADPH → oxidative stress → Heinz body formation → haemolytic anaemia. Test for G6PD deficiency BEFORE prescribing primaquine (used for P. vivax radical cure to eliminate hypnozoites). Common in Mediterranean, African, and South/Southeast Asian populations." },

  // ── PATHOLOGY (IDs 6051–6090) ────────────────────────────────────────────────

  { id:6051, subject:"Pathology", stem:"Coagulative necrosis is characterised by preservation of tissue architecture (ghost outlines) due to protein denaturation. It is the hallmark of necrosis in:", options:["Brain infarct","Myocardial infarction","Pulmonary tuberculosis","Pancreatic fat necrosis"], answer:1, explanation:"Coagulative necrosis: proteins (both structural and enzymatic) are denatured simultaneously → cellular architecture ('ghost outlines') preserved for days to weeks. It is the typical pattern in ischaemic infarction of solid organs (heart, kidney, spleen, liver). Exception: the brain undergoes liquefactive necrosis after ischaemia due to its high water content and relative lack of structural proteins. TB causes caseous necrosis." },
  { id:6052, subject:"Pathology", stem:"A brain abscess on histology shows complete liquefaction of necrotic tissue with loss of all architecture. This type of necrosis is called:", options:["Coagulative necrosis","Caseous necrosis","Liquefactive necrosis","Fat necrosis"], answer:2, explanation:"Liquefactive necrosis occurs when enzymatic digestion dominates over protein denaturation, resulting in complete dissolution of dead tissue into a liquid/semi-liquid mass (pus). It is characteristic of: (1) CNS infarction (self-digestion by lysosomal enzymes from neurons + oligodendrocytes); (2) Bacterial/fungal abscesses (neutrophil-derived enzymes and toxins). The liquefied area becomes a cyst or cavity (in brain) or filled with pus (abscess)." },
  { id:6053, subject:"Pathology", stem:"Caseous necrosis shows 'cheese-like' gross appearance with complete loss of tissue architecture and granuloma formation. It is characteristic of:", options:["Myocardial infarction","Ischaemic stroke","Tuberculosis","Pancreatitis"], answer:2, explanation:"Caseous necrosis ('caseum' = cheese): combined coagulative + liquefactive process where dead tissue has a white-grey crumbly cheese-like gross appearance. Microscopically, there is complete obliteration of normal architecture — only amorphous eosinophilic granular material with surrounding epithelioid granuloma (Langhans giant cells, lymphocytes). Highly characteristic of Mycobacterium tuberculosis and also systemic fungi (Histoplasma, Coccidioides). The lipid-rich mycobacterial wall contributes to the caseous texture." },
  { id:6054, subject:"Pathology", stem:"Fat necrosis in acute pancreatitis produces chalky white deposits due to:", options:["Calcium pyrophosphate crystal deposition","Saponification: released lipase acts on adipose tissue triglycerides → free fatty acids combine with Ca²⁺ → calcium soaps","Uric acid crystal deposition in adipose tissue","Amyloid deposition in peripancreatic fat"], answer:1, explanation:"In acute pancreatitis, activated lipases (especially phospholipase A2) leak into peripancreatic fat → hydrolyse adipocyte triglycerides → release free fatty acids → free fatty acids combine with calcium ions from local tissue → form calcium soaps (saponification). These appear as chalky white, opaque deposits grossly and show basophilic (calcium-staining) deposits in fat cells (ghost adipocytes) on haematoxylin-eosin. Serum calcium may fall (hypocalcaemia — poor prognostic sign)." },
  { id:6055, subject:"Pathology", stem:"Fibrinoid necrosis of vessel walls is characterised by deposition of plasma proteins resembling fibrin. It is most commonly seen in:", options:["Atherosclerotic plaques","Malignant hypertension and vasculitis (e.g., polyarteritis nodosa)","Myocardial infarction","Pulmonary embolism"], answer:1, explanation:"Fibrinoid necrosis: plasma proteins (immunoglobulins, complement, fibrin, albumin) leak into and are deposited in necrotic vascular smooth muscle, staining intensely eosinophilic and fibrin-like on H&E. It is seen in: (1) Malignant hypertension — extreme pressure forces plasma through vessel wall; (2) Vasculitis (polyarteritis nodosa, SLE, rheumatoid arthritis) — immune complex deposition damages vessel wall; (3) Eclampsia. Not a feature of atherosclerosis or thrombosis per se." },
  { id:6056, subject:"Pathology", stem:"Dry gangrene of the toes in a diabetic patient with peripheral vascular disease represents:", options:["Liquefactive necrosis with bacterial superinfection","Caseous necrosis due to mycobacterial infection","Coagulative necrosis due to ischaemia without bacterial infection","Fibrinoid necrosis of digital vessels"], answer:2, explanation:"Dry gangrene = ischaemic coagulative necrosis of a limb without significant bacterial infection. The part is dry, shrunken, mummified, black/brown (haemoglobin breakdown), and sharply demarcated from viable tissue. Occurs in arteriosclerosis and diabetes. Wet gangrene = coexisting bacterial infection → liquefactive component → foul-smelling, soft, swollen. Gas gangrene = Clostridium perfringens infection with crepitus. Wet/gas gangrene require emergency surgical debridement." },
  { id:6057, subject:"Pathology", stem:"In the intrinsic (mitochondrial) pathway of apoptosis, which protein opens the mitochondrial outer membrane pore to release cytochrome c?", options:["BCL-2","BAX and BAK (pro-apoptotic BCL-2 family proteins)","Caspase-8","FADD"], answer:1, explanation:"The intrinsic apoptosis pathway: cellular stress (DNA damage, hypoxia, growth factor withdrawal) → p53 activation → upregulation of pro-apoptotic BCL-2 family proteins (BAX, BAK, BIM) → BAX/BAK oligomerise in the mitochondrial outer membrane (MOMP) → release of cytochrome c + SMAC/DIABLO from mitochondria → cytochrome c forms apoptosome with Apaf-1 + caspase-9 → activates effector caspase-3 → apoptosis. BCL-2 is anti-apoptotic (inhibits BAX/BAK) — overexpressed in follicular lymphoma (t(14;18))." },
  { id:6058, subject:"Pathology", stem:"The extrinsic (death receptor) pathway of apoptosis is initiated when:", options:["DNA double-strand breaks activate p53","FasL (or TNF) binds to Fas (CD95) death receptor → DISC formation → caspase-8 activation","Cytochrome c is released from mitochondria","BCL-2 is downregulated by p53"], answer:1, explanation:"Extrinsic apoptosis pathway: FasL (on cytotoxic T-lymphocytes) binds Fas/CD95 (or TNF binds TNFR1) → death domain clustering → recruitment of FADD (Fas-associated death domain protein) → formation of DISC (Death-Inducing Signalling Complex) → procaspase-8 activation → caspase-8 cleaves effector caspase-3 (or cleaves BID to link to intrinsic pathway). This is how CTLs kill virus-infected cells and how TNF mediates tissue damage in inflammation. TRAIL-TRAIL-R is another death receptor pathway." },
  { id:6059, subject:"Pathology", stem:"Key morphological features of apoptosis that distinguish it from necrosis include:", options:["Cell swelling, membrane rupture, inflammation","Cell shrinkage, chromatin condensation, apoptotic body formation, NO inflammation","Cellular ghosting, calcification, fibrous scarring","Nuclear pyknosis only, without cellular changes"], answer:1, explanation:"Apoptosis features: cell shrinkage (cytoplasmic condensation), chromatin condensation and margination (pyknosis) → karyorrhexis → nuclear fragmentation → apoptotic bodies (membrane-bound fragments containing organelles and nuclear debris) → phagocytosed by adjacent cells/macrophages WITHOUT inflammation (phosphatidylserine 'eat me' signal). Necrosis features: cell swelling, membrane rupture, organelle breakdown, leakage of intracellular contents → inflammatory response. Apoptosis: programmed, physiological/pathological; necrosis: always pathological." },
  { id:6060, subject:"Pathology", stem:"Which cell-derived mediator is most responsible for the immediate vascular permeability increase (wheal and flare) within seconds to minutes of antigen exposure in Type I hypersensitivity?", options:["Prostaglandin E2","Leukotriene C4","Histamine (from mast cell granule degranulation)","Bradykinin"], answer:2, explanation:"Histamine stored in mast cell granules is released within seconds of IgE-mediated mast cell activation → binds H1 receptors on postcapillary venules → endothelial cell contraction → widened intercellular junctions → increased vascular permeability (wheal = oedema) and vasodilation (flare = erythema). This is the IMMEDIATE phase (seconds to minutes). The late phase (4-8 hours) is driven by newly synthesised mediators: leukotrienes, prostaglandins, cytokines. Bradykinin acts similarly but is from plasma kinin system." },
  { id:6061, subject:"Pathology", stem:"Leukotriene B4 (LTB4) is a potent chemoattractant primarily for which cell type?", options:["Eosinophils","Lymphocytes","Neutrophils","Mast cells"], answer:2, explanation:"LTB4 is produced by the 5-lipoxygenase pathway from arachidonic acid in neutrophils and macrophages. It is one of the most potent chemotactic agents for neutrophils — activating their integrin expression, causing them to migrate to sites of inflammation. LTC4, LTD4, and LTE4 (cysteinyl leukotrienes) cause bronchoconstriction and increased vascular permeability. Eotaxin and IL-5 are major eosinophil chemoattractants. LTB4 is the main leukotriene for neutrophil recruitment." },
  { id:6062, subject:"Pathology", stem:"Interleukin-1 (IL-1) and TNF-α are the principal mediators of the systemic acute phase response. These cytokines cause fever by:", options:["Directly acting on peripheral pain receptors","Stimulating hypothalamic prostaglandin E2 (PGE2) synthesis via COX-2 → raises the thermoregulatory set point","Activating natural killer cells to produce pyrogens","Increasing cAMP in hypothalamic neurons directly"], answer:1, explanation:"IL-1, TNF-α, and IL-6 (endogenous pyrogens) act on hypothalamic vascular endothelium and glial cells → upregulate COX-2 → produce PGE2 → PGE2 binds EP3 receptors on hypothalamic thermoregulatory neurons → raises temperature set point → fever. NSAIDs (COX inhibitors) reduce fever by blocking PGE2 synthesis. Acetaminophen also reduces hypothalamic PGE2 but through different mechanism. Malaria parasites, bacterial products (LPS via IL-1/TNF) also raise temperature this way." },
  { id:6063, subject:"Pathology", stem:"Bradykinin is an important mediator of pain and vascular permeability. Which enzyme is responsible for bradykinin degradation, and what happens when this enzyme is inhibited?", options:["Renin; inhibition causes fluid retention","ACE (angiotensin-converting enzyme); inhibition causes bradykinin accumulation → ACE inhibitor-associated dry cough and angioedema","Kallikrein; inhibition causes reduced bradykinin synthesis","C1-esterase; inhibition causes hereditary angioedema"], answer:1, explanation:"Bradykinin is degraded by ACE (kininase II) in the lung. ACE inhibitors (enalapril, lisinopril) block both: (1) angiotensin I → II conversion AND (2) bradykinin degradation. Accumulated bradykinin → stimulates C-fibre cough receptors → ACE-inhibitor dry cough (occurs in ~10-15%; more common in Asian populations). Severe bradykinin accumulation → angioedema (face, larynx — life-threatening, does NOT respond to epinephrine, managed with icatibant/fresh frozen plasma/C1-inhibitor concentrate). Switch to ARB avoids bradykinin accumulation." },
  { id:6064, subject:"Pathology", stem:"Alpha-fetoprotein (AFP) is elevated in which of the following malignancies?", options:["Testicular seminoma","Hepatocellular carcinoma (HCC)","Choriocarcinoma","Medullary thyroid carcinoma"], answer:1, explanation:"AFP is normally produced by the yolk sac, foetal liver, and GI tract. Elevated in: (1) HCC (>90% of cases, especially with cirrhosis — AFP >400 ng/mL is virtually diagnostic); (2) Testicular germ cell tumours — yolk sac tumour (endodermal sinus tumour), most common cause in children; (3) Gastric cancer (some). Seminoma does NOT produce AFP (beta-hCG only). Choriocarcinoma produces β-hCG. Medullary thyroid carcinoma produces calcitonin. AFP also elevated in neural tube defects (amniotic fluid, maternal serum)." },
  { id:6065, subject:"Pathology", stem:"The tumour marker most useful for monitoring response to chemotherapy in choriocarcinoma and gestational trophoblastic disease is:", options:["CEA","CA-125","Beta-hCG (beta human chorionic gonadotrophin)","AFP"], answer:2, explanation:"β-hCG is produced by syncytiotrophoblasts. It is the ideal marker for gestational trophoblastic disease (GTD): choriocarcinoma, complete hydatidiform mole, partial mole. It has exquisite sensitivity and specificity — even small amounts of residual disease cause detectable β-hCG elevation. Used for: initial diagnosis, monitoring response (should fall with treatment), detecting relapse. β-hCG also elevated in: testicular choriocarcinoma, some seminomas (10-15%), rarely other GCTs. AFP is the marker for yolk sac tumour." },
  { id:6066, subject:"Pathology", stem:"PSA (prostate-specific antigen) elevation in a 60-year-old man is most likely due to:", options:["Prostate cancer exclusively — PSA is absolutely specific for cancer","Benign prostatic hyperplasia (BPH), prostatitis, or prostate cancer — PSA is organ-specific NOT cancer-specific","Bladder cancer causing compression of prostate","Renal cell carcinoma metastasising to prostate"], answer:1, explanation:"PSA is produced by normal and malignant prostate epithelium — it is ORGAN-SPECIFIC but NOT CANCER-SPECIFIC. PSA elevation occurs in: prostate cancer, BPH, prostatitis, prostate biopsy/manipulation, urinary retention. Useful for: monitoring after prostate cancer treatment (rises indicate recurrence), screening (PSA >4 ng/mL warrants biopsy, but many false positives). Free:total PSA ratio helps: lower ratio suggests cancer. PSA velocity (rate of rise) also informative. PSA alone cannot diagnose prostate cancer — biopsy required." },
  { id:6067, subject:"Pathology", stem:"CA-125 is elevated in ovarian carcinoma. Which benign gynaecological condition also causes CA-125 elevation, making it non-specific?", options:["Leiomyoma (fibroid)","Endometriosis","Polycystic ovary syndrome","Cervical ectropion"], answer:1, explanation:"CA-125 (a glycoprotein expressed by celomic epithelium) is elevated in: epithelial ovarian cancer (mainly serous type, sensitivity ~80% for advanced disease), endometriosis, pelvic inflammatory disease, pregnancy (first trimester), liver cirrhosis, pleural/pericardial effusions. CA-125 is most useful for monitoring treatment response and detecting recurrence in known ovarian cancer, not for screening (low specificity in pre-menopausal women). CA 19-9 is for pancreatic/biliary cancer; CEA for colorectal cancer." },
  { id:6068, subject:"Pathology", stem:"CA 19-9 tumour marker is most useful in monitoring which gastrointestinal malignancy?", options:["Colorectal cancer","Hepatocellular carcinoma","Pancreatic cancer and cholangiocarcinoma","Gastric cancer"], answer:2, explanation:"CA 19-9 (sialylated Lewis blood group antigen) is the most commonly used marker for pancreatic adenocarcinoma (sensitivity ~80% for advanced disease) and cholangiocarcinoma. However it is NOT specific: elevated in benign conditions (pancreatitis, cholangitis, cirrhosis). It is used for: monitoring treatment response, detecting recurrence, pre-operative staging. Note: CA 19-9 cannot be produced by Lewis antigen-negative blood group patients (5-10% of population) — false negative. CEA is primary marker for colorectal cancer; AFP for HCC." },
  { id:6069, subject:"Pathology", stem:"Calcitonin is the tumour marker for medullary thyroid carcinoma (MTC). MTC arises from which thyroid cell type?", options:["Follicular cells (thyrocytes)","Parafollicular C cells","Hurthle cells","Lymphocytes in thyroid"], answer:1, explanation:"MTC arises from parafollicular C cells (derived from neural crest), which normally secrete calcitonin. Calcitonin is the specific marker for MTC: serum calcitonin is elevated proportionally to tumour burden; used for screening (especially in MEN2A/2B families — RET proto-oncogene mutation), monitoring post-thyroidectomy (should be undetectable), detecting recurrence. CEA also elevated in MTC (useful when calcitonin is paradoxically low). MEN2A: MTC + phaeochromocytoma + parathyroid hyperplasia. MEN2B: MTC + phaeochromocytoma + marfanoid + mucosal neuromas." },
  { id:6070, subject:"Pathology", stem:"Chromogranin A is a tumour marker for:", options:["Hepatocellular carcinoma","Neuroendocrine tumours (carcinoid, phaeochromocytoma, islet cell tumours)","Germ cell tumours","Renal cell carcinoma"], answer:1, explanation:"Chromogranin A is an acidic protein stored in dense-core secretory granules of neuroendocrine cells. It is elevated in neuroendocrine tumours (NETs): carcinoid tumours (GI tract, lung), phaeochromocytoma/paraganglioma, pancreatic NETs (insulinoma, gastrinoma, VIPoma, glucagonoma), Merkel cell carcinoma, small cell lung cancer. Synaptophysin is another neuroendocrine marker. S-100 protein is a marker for melanoma, Schwannoma, astrocytoma, histiocytosis X, and is used in immunohistochemistry." },
  { id:6071, subject:"Pathology", stem:"On Congo red staining of tissue from a patient with chronic renal failure and multiple myeloma, deposits show apple-green birefringence under polarised light. The diagnosis is:", options:["Calcium pyrophosphate crystal deposition (CPPD)","Amyloidosis (AL amyloid in this context)","Uric acid (gout)","Oxalosis"], answer:1, explanation:"Amyloid: Congo red stain → pink/red deposits on H&E; under polarised light → apple-green birefringence (pathognomonic). Types of amyloid in context: AL amyloid (immunoglobulin light chains; in multiple myeloma/primary amyloidosis — affects heart, kidney, liver, tongue [macroglossia], peripheral nerves), AA amyloid (serum amyloid A protein; in chronic inflammatory conditions — affects kidney predominantly). Biopsy sites: rectum, abdominal fat pad (least invasive, high sensitivity), kidney." },
  { id:6072, subject:"Pathology", stem:"AA amyloid (secondary/reactive amyloid) is composed of which protein, and in which clinical settings does it arise?", options:["Immunoglobulin light chains in multiple myeloma","Serum amyloid A (SAA) protein — an acute phase reactant — in chronic inflammatory conditions (RA, TB, osteomyelitis, Crohn's disease, familial Mediterranean fever)","Transthyretin in cardiac amyloidosis","Beta-2 microglobulin in dialysis patients"], answer:1, explanation:"AA amyloid: derived from SAA (serum amyloid A), an acute phase reactant produced by liver in response to IL-1, TNF-α, IL-6. In chronic inflammation, persistently elevated SAA → amyloid fibrils deposit in kidney (glomeruli → nephrotic syndrome), liver, spleen, adrenals. Causes: RA (most common in Western countries), chronic TB, osteomyelitis, bronchiectasis, Crohn's, familial Mediterranean fever, Castleman's disease. Treatment of underlying disease can slow/halt progression. Beta-2 microglobulin amyloid (Aβ₂M): long-term haemodialysis (carpal tunnel syndrome)." },
  { id:6073, subject:"Pathology", stem:"Auer rods are pathognomonic of which haematological malignancy?", options:["Acute lymphoblastic leukaemia (ALL)","Chronic myeloid leukaemia (CML)","Acute myeloid leukaemia (AML)","Multiple myeloma"], answer:2, explanation:"Auer rods are needle-shaped or crystalline red-staining inclusions in the cytoplasm of myeloid blasts (and promyelocytes), formed by abnormal coalescence of azurophilic granules (primary lysosomes containing myeloperoxidase). They are PATHOGNOMONIC of AML (especially AML-M3 [acute promyelocytic leukaemia/APL], where 'faggot cells' contain bundles of Auer rods). They are NEVER seen in ALL. Myeloperoxidase (MPO) stain positive confirms myeloid lineage. APL (t(15;17), PML-RARA) carries risk of DIC and responds to ATRA + arsenic trioxide." },
  { id:6074, subject:"Pathology", stem:"Terminal deoxynucleotidyl transferase (TdT) positivity is used to confirm which diagnosis?", options:["AML (acute myeloid leukaemia)","CML (chronic myeloid leukaemia) blast crisis","ALL (acute lymphoblastic leukaemia)","Hairy cell leukaemia"], answer:2, explanation:"TdT (terminal deoxynucleotidyl transferase) is a specialised DNA polymerase expressed in immature (precursor) lymphoid cells — it adds random nucleotides during V(D)J recombination to generate antibody/TCR diversity. TdT positivity distinguishes lymphoblasts (ALL) from myeloblasts (AML, TdT negative). In B-ALL: also CD10 (CALLA), CD19, CD79a+. In T-ALL: CD3, CD7+. ALL is the most common malignancy in children (peak 2-5 years), presents with bone marrow failure symptoms (anaemia, bleeding, infections) + lymphadenopathy + mediastinal mass (T-ALL)." },
  { id:6075, subject:"Pathology", stem:"The Philadelphia chromosome t(9;22) creating BCR-ABL fusion gene is characteristic of which leukaemia?", options:["Acute lymphoblastic leukaemia (ALL) in children","Chronic myeloid leukaemia (CML)","Acute promyelocytic leukaemia (APL)","Chronic lymphocytic leukaemia (CLL)"], answer:1, explanation:"CML: translocation t(9;22) moves ABL (9q34) to BCR (22q11.2) → Philadelphia chromosome (Ph+) → BCR-ABL fusion protein with constitutively active tyrosine kinase → uncontrolled myeloid proliferation. Blood film: leucocytosis (WBC often >100,000), all myeloid stages (left shift), basophilia (characteristic), eosinophilia, myelocytes in blood. Leucocyte alkaline phosphatase (LAP) score: LOW (vs. leukaemoid reaction where LAP is high). Treatment: imatinib (first-generation TKI) — tyrosine kinase inhibitor. Ph+ ALL also occurs (~25% adults, poor prognosis)." },
  { id:6076, subject:"Pathology", stem:"Smudge cells (smear cells) on blood film are characteristically seen in:", options:["AML","CML","CLL (chronic lymphocytic leukaemia)","Myeloma"], answer:2, explanation:"CLL: monoclonal proliferation of mature-appearing small B lymphocytes (CD5+, CD19+, CD20dim, CD23+, weak surface Ig). Blood film: lymphocytosis (>5000/mm³) of small, round, mature lymphocytes with clumped chromatin. SMUDGE/SMEAR CELLS: fragile CLL cells crushed during film preparation, appearing as amorphous nuclear material without cytoplasm — hallmark of CLL. Complications: autoimmune haemolytic anaemia (Coombs+), hypogammaglobulinaemia, Richter's transformation (into aggressive DLBCL — bad prognosis). CLL is most common adult leukaemia in Western countries." },
  { id:6077, subject:"Pathology", stem:"Richter's transformation in CLL refers to:", options:["Transformation of CLL to AML","Transformation of CLL to an aggressive large B-cell lymphoma (DLBCL) or Hodgkin lymphoma","Spontaneous remission of CLL","Blast crisis similar to CML"], answer:1, explanation:"Richter's transformation (Richter's syndrome) occurs in ~2-10% of CLL patients: the indolent CLL clone transforms into an aggressive lymphoma, most commonly diffuse large B-cell lymphoma (DLBCL) or rarely Hodgkin lymphoma. Clinically: sudden rapid enlargement of lymph nodes, systemic B symptoms (fever, night sweats, weight loss), elevated LDH. Median survival after Richter's transformation is <1 year. Similar transformation can occur in follicular lymphoma → DLBCL (most common secondary lymphoma transformation)." },
  { id:6078, subject:"Pathology", stem:"In Hodgkin lymphoma, Reed-Sternberg (RS) cells are pathognomonic. The classic RS cell appearance is:", options:["Small lymphocyte with cleaved nucleus","Large cell with bilobed nucleus and prominent 'owl-eye' nucleoli, surrounded by a clear halo in a background of mixed inflammatory cells","Plasma cell with clock-face chromatin and Dutcher bodies","Small cleaved cell with 'starry sky' pattern"], answer:1, explanation:"Reed-Sternberg cells: large binucleated or bilobed cells with prominent eosinophilic 'owl-eye' nucleoli, surrounded by a clear halo (lacunar variant in nodular sclerosis subtype). They are derived from B lymphocytes (CD15+, CD30+ 'targeting antigens'; CD20-, CD45- typically). Present in a reactive background of lymphocytes, eosinophils, plasma cells, neutrophils. Hodgkin lymphoma subtypes: Nodular Sclerosis (most common, young females, anterior mediastinum), Mixed Cellularity, Lymphocyte Rich, Lymphocyte Depleted (worst prognosis). EBV association: Mixed Cellularity subtype." },
  { id:6079, subject:"Pathology", stem:"The 'starry sky' pattern on histology is characteristic of which lymphoma?", options:["Nodular sclerosis Hodgkin lymphoma","Follicular lymphoma","Burkitt lymphoma","Marginal zone lymphoma"], answer:2, explanation:"Burkitt lymphoma: sheets of intermediate-sized monotonous lymphoblasts (B-cells) with numerous mitoses (high proliferation index — Ki-67 nearly 100%) and scattered macrophages containing ingested apoptotic debris → clear cytoplasmic spaces (macrophages) against a dark background of tumour cells = 'STARRY SKY' pattern. Translocation: t(8;14) — MYC oncogene overexpression. EBV association: endemic (African jaw) form. Highly aggressive but potentially curable with intensive chemotherapy (CODOX-M/IVAC or CHOP + rituximab). Lactic acidosis and tumour lysis syndrome common." },
  { id:6080, subject:"Pathology", stem:"Follicular lymphoma is associated with which chromosomal translocation leading to BCL-2 overexpression?", options:["t(9;22) BCR-ABL","t(8;14) MYC","t(14;18) BCL-2","t(11;14) Cyclin D1/BCL-1"], answer:2, explanation:"Follicular lymphoma: t(14;18) — BCL-2 gene (chromosome 18) translocated to IgH locus (chromosome 14) → BCL-2 overexpressed → anti-apoptotic → cells accumulate. Low-grade, indolent course (median survival >10 years untreated), but incurable except with stem cell transplantation. On biopsy: follicular (nodular) growth pattern of centrocytes (small cleaved) and centroblasts. CD10+, BCL-6+, BCL-2+, CD20+. Can transform to DLBCL (Richter-like). t(11;14): Mantle cell lymphoma (cyclin D1). t(8;14): Burkitt. t(2;5): ALK+ ALCL (anaplastic large cell lymphoma)." },
  { id:6081, subject:"Pathology", stem:"Granulomas in tuberculosis are composed of which cell type as the central component?", options:["Neutrophils","Epithelioid macrophages (derived from monocytes, activated by IFN-γ) with Langhans giant cells","Eosinophils","Plasma cells"], answer:1, explanation:"TB granuloma (caseating granuloma): EPITHELIOID MACROPHAGES (activated by Th1-derived IFN-γ → lose phagocytic vacuoles, cytoplasm resembles epithelial cells) form the central aggregate with Langhans giant cells (macrophage fusion; horseshoe/peripheral nuclear arrangement — vs. foreign body giant cells with central nuclear arrangement) surrounded by lymphocytes (CD4+ Th1), fibroblasts, and collagen. Central caseous necrosis (cheese-like). Non-caseating granulomas: sarcoidosis, Crohn's, berylliosis. IFN-gamma release assays (IGRAs) detect sensitised T-cells." },
  { id:6082, subject:"Pathology", stem:"Which pattern of hepatocellular necrosis is seen in right heart failure (congestive heart failure)?", options:["Zone 1 (periportal) necrosis","Zone 2 (mid-zone) necrosis","Zone 3 (centrilobular) necrosis","Panacinar necrosis"], answer:2, explanation:"Zone 3 (centrilobular) necrosis occurs in conditions with reduced oxygen delivery to zone 3 hepatocytes (furthest from portal blood supply, most vulnerable to ischaemia): right heart failure (back-pressure → hepatic venous congestion → reduced perfusion), ischaemic hepatitis ('shock liver'). Zone 1 (periportal): phosphorus poisoning, eclampsia, yellow fever. Zone 2 (mid-zone): yellow fever (historically described). Panacinar: fulminant viral hepatitis, halothane toxicity. Paracetamol: zone 3 (centrilobular) necrosis also." },
  { id:6083, subject:"Pathology", stem:"The most sensitive marker of glomerular filtration rate (GFR) and earliest marker of renal damage is:", options:["Serum creatinine","24-hour urinary protein","Serum cystatin C","Blood urea nitrogen (BUN)"], answer:2, explanation:"Cystatin C is a low-molecular-weight protein produced at a constant rate by all nucleated cells, freely filtered by glomeruli, completely reabsorbed and catabolised by tubular cells (none secreted). It is a more sensitive marker of GFR than creatinine (which requires significant GFR loss before rising, and is affected by muscle mass, diet, tubular secretion). Cystatin C rises earlier in AKI and CKD. Microalbuminuria (30-300 mg/day) is the earliest clinical marker of diabetic nephropathy. UACR (urine albumin:creatinine ratio) is now standard." },
  { id:6084, subject:"Pathology", stem:"Karyolysis, pyknosis, and karyorrhexis are nuclear changes seen in:", options:["Apoptosis only (pyknosis → karyorrhexis → apoptotic body)","Necrosis only (pyknosis → karyorrhexis → karyolysis)","Both apoptosis and necrosis (early stages overlap)","Neither — these are cytoplasmic changes"], answer:1, explanation:"Nuclear changes in cell death: PYKNOSIS — nuclear shrinkage with chromatin condensation (dense, small, darkly staining); KARYORRHEXIS — fragmentation of pyknotic nucleus into small pieces; KARYOLYSIS — fading of nuclear staining due to DNase activation (dissolution of chromatin). Sequence in NECROSIS: pyknosis → karyorrhexis → karyolysis → complete dissolution. In APOPTOSIS: pyknosis and karyorrhexis occur but nucleus fragments are contained within apoptotic bodies; karyolysis does not occur in classical apoptosis." },
  { id:6085, subject:"Pathology", stem:"Which type of giant cell has nuclei arranged in a horseshoe/peripheral pattern and is specifically associated with tuberculosis?", options:["Touton giant cell (seen in xanthoma/fat necrosis)","Langhans giant cell (peripheral/horseshoe nuclear arrangement)","Foreign body giant cell (random nuclear arrangement)","Reed-Sternberg cell (mirror-image bilobed nuclei)"], answer:1, explanation:"Langhans giant cell (not to be confused with Langerhans cell of skin): multinucleated giant cell formed by macrophage fusion in granulomatous inflammation, specifically in response to mycobacteria. Nuclei are arranged at the PERIPHERY in a horseshoe/ring pattern. Seen in: TB, sarcoidosis, leprosy, berylliosis, Crohn's. FOREIGN BODY giant cell: irregular, randomly arranged nuclei; formed around inert foreign material. Touton giant cell: nuclei in a ring, with foamy lipid-laden cytoplasm beyond the ring; seen in xanthogranulomas, fat necrosis." },
  { id:6086, subject:"Pathology", stem:"p53 is a tumour suppressor gene. Loss of p53 function most directly results in:", options:["Uncontrolled growth factor signalling","Inability to repair DNA damage or undergo apoptosis → cells with DNA damage proliferate (genome guardian failure)","Overexpression of BCL-2 anti-apoptotic protein","Constitutive activation of RAS pathway"], answer:1, explanation:"p53 ('guardian of the genome') is activated by DNA damage, hypoxia, oncogene activation → p53 transcribes: CDKN1A/p21 (cell cycle arrest at G1), BAX/PUMA/NOXA (apoptosis), GADD45 (DNA repair). Loss of p53 (mutation: most common oncogenic mutation, >50% of human cancers; Li-Fraumeni syndrome: germline p53 mutation) → cells with DNA damage cannot arrest or apoptose → accumulate mutations → cancer. HPV E6 protein degrades p53 (cervical cancer). p53 mutation detected by immunohistochemistry (accumulates due to MDM2 inactivation)." },
  { id:6087, subject:"Pathology", stem:"Which paraneoplastic syndrome is caused by small cell lung carcinoma (SCLC) producing ectopic ADH?", options:["Cushing syndrome (ectopic ACTH)","Syndrome of inappropriate ADH (SIADH) — hyponatraemia with inappropriately concentrated urine","Hypercalcaemia (ectopic PTHrP)","Polycythaemia (ectopic erythropoietin)"], answer:1, explanation:"SCLC (neuroendocrine tumour, most associated with paraneoplastic syndromes): ectopic ADH production → SIADH → dilutional hyponatraemia (low serum Na+, but inappropriately concentrated urine [Uosm >100 mOsm/kg]). Also SCLC produces: ectopic ACTH → Cushing syndrome. Other paraneoplastic: Squamous cell lung cancer → PTHrP → hypercalcaemia; Renal cell carcinoma → EPO → polycythaemia; Hepatocellular carcinoma → IGF-2 → hypoglycaemia; Thymoma → myasthenia gravis; SCLC → Lambert-Eaton syndrome (anti-VGCC antibodies → reduced ACh release → proximal muscle weakness)." },
  { id:6088, subject:"Pathology", stem:"Metaplasia is defined as:", options:["Increase in cell number (hyperplasia)","Replacement of one differentiated cell type by another differentiated cell type better suited to a new environment","Loss of cell differentiation (anaplasia/dysplasia)","Irreversible cell injury leading to cell death"], answer:1, explanation:"Metaplasia: reversible change in which one mature cell type is replaced by another mature cell type, usually as an adaptive response to chronic irritation or stress. Examples: (1) Barrett's oesophagus — squamous epithelium → intestinal columnar metaplasia due to acid reflux (GERD); (2) Cervical ectropion — columnar → squamous at transformation zone; (3) Respiratory tract in smokers — columnar ciliated → squamous; (4) Bladder in Schistosoma — transitional → squamous. Metaplasia ITSELF is reversible, but the underlying stimulus increases cancer risk (dysplasia → carcinoma). Regulated by transcription factors (SOX2, CDX2)." },
  { id:6089, subject:"Pathology", stem:"Dysplasia is characterised by which histological features?", options:["Normal cellular architecture with increased cell number","Abnormal cellular and architectural maturation: nuclear pleomorphism, increased N:C ratio, abnormal mitoses, loss of polarity — without invasion through basement membrane","Replacement of one cell type by another","Full-thickness abnormality with stromal invasion"], answer:1, explanation:"Dysplasia: disordered growth with loss of normal differentiation and architecture. Features: nuclear pleomorphism (variation in size and shape), hyperchromatism, increased N:C ratio, abnormal mitoses (tripolar, ring mitoses), loss of cell polarity, crowding. CONFINED WITHIN EPITHELIUM (no invasion through basement membrane) = 'carcinoma in situ' (CIS) = dysplasia grade III. Mild dysplasia may regress; moderate/severe dysplasia is a significant cancer precursor. When dysplastic cells break through basement membrane → invasive carcinoma (with metastatic potential)." },
  { id:6090, subject:"Pathology", stem:"Virchow's triad of factors predisposing to venous thrombosis consists of:", options:["Hypertension + hyperlipidaemia + diabetes","Endothelial injury + abnormal blood flow (stasis/turbulence) + hypercoagulability","Atherosclerosis + platelet activation + fibrin clot","Arterial spasm + endothelitis + thrombocytopenia"], answer:1, explanation:"Virchow's triad (1856): (1) ENDOTHELIAL INJURY — exposes subendothelial collagen/tissue factor (main in arterial thrombosis — MI, stroke); (2) ABNORMAL BLOOD FLOW — stasis (DVT in immobility, cardiac chambers in AF) or turbulence (atherosclerotic plaques, aneurysms); (3) HYPERCOAGULABILITY — inherited (Factor V Leiden, prothrombin mutation, protein C/S deficiency, antithrombin deficiency) or acquired (OCP, malignancy, antiphospholipid syndrome, pregnancy). In venous thrombosis: stasis + hypercoagulability predominate. In arterial thrombosis: endothelial injury + turbulence predominate." },

  // ── MICROBIOLOGY (IDs 6091–6120) ─────────────────────────────────────────────

  { id:6091, subject:"Microbiology", stem:"Mycobacterium tuberculosis is grown in the laboratory on which specialised culture medium, producing cream/buff colonies after 6-8 weeks?", options:["Blood agar","Lowenstein-Jensen (LJ) medium containing malachite green (inhibits contaminants) and egg-based nutrients","MacConkey agar","Thayer-Martin medium"], answer:1, explanation:"Lowenstein-Jensen (LJ) medium: contains coagulated egg (nutrient source), glycerol (enhances growth of M. tuberculosis), malachite green (inhibits other bacteria and fungi). M. tuberculosis grows slowly — 6-8 weeks — producing raised, dry, rough, cream/buff ('breadcrumb') colonies. M. bovis grows better without glycerol. Liquid culture systems (MGIT — Mycobacterial Growth Indicator Tube) are faster (1-2 weeks) and now preferred. BCG (M. bovis BCG) grows on LJ as smooth colonies." },
  { id:6092, subject:"Microbiology", stem:"Bordetella pertussis (causative agent of whooping cough) is cultured on which medium producing 'mercury drop' colonies?", options:["MacConkey agar","Lowenstein-Jensen medium","Bordet-Gengou (BG) agar (potato-glycerol-blood medium)","TCBS agar"], answer:2, explanation:"Bordet-Gengou agar: potato extract + glycerol + blood (15-20%). B. pertussis grows as smooth, shiny, 'mercury drop' (silver coin) colonies in 3-5 days under aerobic conditions. The blood in BG agar produces a zone of haemolysis around colonies. X-pert medium (Regan-Lowe charcoal-horse blood) is also used. Nasopharyngeal swab/aspirate is the specimen of choice (taken in first 2 weeks — peroxidase stage). PCR is now the most sensitive diagnostic method. Vaccine: acellular pertussis (DTaP/Tdap) — contains PT, FHA, pertactin." },
  { id:6093, subject:"Microbiology", stem:"Thayer-Martin medium is used to culture which fastidious organisms from clinical specimens containing normal flora?", options:["Mycobacterium tuberculosis","Neisseria gonorrhoeae and N. meningitidis","Haemophilus influenzae","Vibrio cholerae"], answer:1, explanation:"Thayer-Martin medium: chocolate agar base (heated blood → releases V and X factors) enriched with nutrients + VCN (Vancomycin [gram-positive suppression], Colistin [gram-negative suppression], Nystatin [fungal suppression]). This selective medium allows only Neisseria species to grow from specimens containing commensals (e.g., genital, throat, CSF specimens). Modified Thayer-Martin (MTM) also contains trimethoprim to suppress Proteus. Chocolate agar alone is used for H. influenzae (requires factors V and X, released by heating blood)." },
  { id:6094, subject:"Microbiology", stem:"Haemophilus influenzae requires which two growth factors and therefore grows best on chocolate agar?", options:["Factors I and II (fibrinogen and thrombin)","Factors V (NAD) and X (haemin/haemin)","Factors A and B (complement components)","Factors VII and VIII (coagulation factors)"], answer:1, explanation:"H. influenzae is fastidious and requires: FACTOR V (NAD, nicotinamide adenine dinucleotide) — a coenzyme needed for aerobic respiration; FACTOR X (haemin, protoporphyrin IX) — needed for cytochrome synthesis. Both factors are present inside red blood cells and released when RBCs are heated (lysis during chocolate agar preparation). On blood agar alone, H. influenzae doesn't grow well (factors V trapped inside RBCs). Satellite phenomenon: H. influenzae grows around Staphylococcus aureus colonies on blood agar (S. aureus lyses RBCs releasing both factors and secretes factor V)." },
  { id:6095, subject:"Microbiology", stem:"CLED medium (cystine-lactose-electrolyte-deficient agar) is used for urine culture. Its main advantage over blood agar is:", options:["It selects for gram-positive bacteria only","It inhibits swarming of Proteus species (which lack K+ for swarming) while supporting growth of all urinary pathogens","It detects methicillin-resistant Staphylococcus aureus (MRSA)","It is used for growth of fastidious anaerobes"], answer:1, explanation:"CLED medium: cystine (enhances growth of dwarf colony E. coli), lactose (fermenters produce yellow colonies, non-fermenters produce blue-green colonies), electrolyte-deficient (no K+/Na+) — this inhibits the swarming of Proteus mirabilis which requires K+ for flagella-driven swarming motility. This prevents Proteus overgrowth that would obscure other pathogens on blood/MacConkey agar. E. coli (yellow), Proteus (translucent/blue), Pseudomonas (green), Enterococcus (yellow/turquoise). Standard for urine culture alongside MacConkey agar." },
  { id:6096, subject:"Microbiology", stem:"Vibrio cholerae produces yellow colonies on TCBS (thiosulfate-citrate-bile-sucrose) agar because:", options:["It is gram-positive and reduces tellurite","It ferments sucrose (sucrose-positive Vibrio), producing acid that turns the pH indicator yellow","It produces hydrogen sulphide from thiosulfate","It is oxidase-negative and catalase-positive"], answer:1, explanation:"TCBS agar: selective and differential for Vibrio. V. cholerae ferments SUCROSE → acid production → pH indicator (bromothymol blue) turns YELLOW — yellow colonies (El Tor biotype and classical biotype both sucrose+). V. parahaemolyticus (non-sucrose fermenter) → BLUE-GREEN colonies. TCBS contains: thiosulfate + citrate (inhibit gram-positive bacteria and enterobacteriaceae), bile salts (inhibit gram-positives), sucrose (differential). V. cholerae: comma-shaped gram-negative bacillus, oxidase positive, grows in alkaline peptone water (APW, enrichment broth), produces CT (cholera toxin) causing rice-water diarrhoea." },
  { id:6097, subject:"Microbiology", stem:"Corynebacterium diphtheriae grows as grey-black colonies on Tellurite agar (Hoyle's medium). The grey-black colour is due to:", options:["Melanin production","Reduction of potassium tellurite to metallic tellurium deposited within the cell","Hydrogen sulphide gas production reacting with iron","Haemoglobin degradation"], answer:1, explanation:"C. diphtheriae reduces potassium tellurite to metallic tellurium → deposits as black granules intracellularly → grey-black colonies on Hoyle's medium. On Loeffler's serum slope: grows as cream/white colonies with characteristic 'Chinese-letter'/cuneiform arrangement of bacilli. Albert stain shows metachromatic granules (volutin/Babes-Ernst granules) at poles → 'dumbbell' or 'club-shaped' appearance. Elek's test (immunodiffusion) and PCR used to demonstrate toxin production. Toxin: A-B toxin — B subunit binds, A subunit ADP-ribosylates EF-2 → protein synthesis inhibition → pseudomembrane." },
  { id:6098, subject:"Microbiology", stem:"In the Gram stain procedure, the step that determines whether bacteria are gram-positive or gram-negative is:", options:["Application of crystal violet (primary stain)","Application of Gram's iodine (mordant)","Decolourisation with acetone-alcohol","Application of safranin (counterstain)"], answer:2, explanation:"Gram stain sequence: (1) Crystal violet — primary stain, stains all bacteria purple; (2) Gram's iodine — mordant, forms crystal violet-iodine (CVI) complex in peptidoglycan; (3) Acetone-alcohol DECOLOURISER — KEY STEP: gram-positive bacteria: thick peptidoglycan + no outer membrane → CVI complex retained → purple; gram-negative bacteria: thin peptidoglycan + outer membrane + lipids dissolved by acetone-alcohol → CVI lost → colourless; (4) Safranin counterstain → gram-negatives stain red/pink. Over-decolourisation makes gram-positives appear gram-negative (false results)." },
  { id:6099, subject:"Microbiology", stem:"Ziehl-Neelsen (ZN) stain is used to identify acid-fast bacilli (AFB). Mycobacteria appear which colour on ZN stain?", options:["Blue bacilli on red background","Red/pink bacilli on blue background","Green bacilli on purple background","Black bacilli on yellow background"], answer:1, explanation:"ZN staining: (1) Carbol fuchsin (primary stain — heated 'hot ZN') or concentrated carbol fuchsin (cold Kinyoun) → penetrates mycolic acid-rich cell wall of mycobacteria; (2) Acid-alcohol decolouriser (3% HCl in 95% ethanol) → removes carbol fuchsin from non-AFB but not from mycobacteria (mycolic acids resist decolourisation = 'acid-fastness'); (3) Methylene blue counterstain. AFB (TB, Leprosy, Nocardia partially) = RED/PINK on BLUE background. Leprosy bacilli are AFB on ZN; Nocardia: weakly acid-fast (using 1% H2SO4 decolouriser — modified ZN). FITE stain for leprosy tissue sections." },
  { id:6100, subject:"Microbiology", stem:"India ink preparation is used to demonstrate the capsule of Cryptococcus neoformans. The appearance on India ink preparation is:", options:["Red yeast cells on black background","Budding yeast cells with a clear halo (capsule) against black background","Branching hyphae with septae on black background","Gram-positive cocci in clusters on black background"], answer:1, explanation:"India ink preparation (negative staining): India ink particles are too large to penetrate the cryptococcal capsule → capsule appears as a clear (unstained) halo around the yeast cell against the dark background. C. neoformans: encapsulated budding yeast (narrow neck budding), found in pigeon droppings, soil. In immunocompromised (especially HIV with CD4<100): causes cryptococcal meningitis. Diagnosis: India ink of CSF (quick), cryptococcal antigen (latex agglutination or lateral flow assay — highly sensitive), culture on Sabouraud's. Treatment: amphotericin B + flucytosine → fluconazole." },
  { id:6101, subject:"Microbiology", stem:"PAS (Periodic acid-Schiff) stain is used in microbiology and histopathology to identify:", options:["Acid-fast organisms","Fungi (stains polysaccharide cell wall) and glycogen-rich organisms","Spirochaetes (Treponema pallidum)","Gram-negative bacteria only"], answer:1, explanation:"PAS stain: periodic acid oxidises adjacent hydroxyl groups in polysaccharides and glycoproteins → creates aldehydes → Schiff reagent reacts with aldehydes → magenta/purple colour. Identifies: (1) FUNGI — polysaccharide-rich cell walls (Candida, Aspergillus, Histoplasma, Pneumocystis [controversial]); (2) Tropheryma whipplei (Whipple's disease — PAS-positive macrophages in lamina propria); (3) Glycogen (in cells); (4) Mucin. Also used in renal biopsy to highlight GBM and mesangium. GMS (Gomori methenamine silver) also stains fungi (black on green background) — complementary to PAS." },
  { id:6102, subject:"Microbiology", stem:"In hepatitis B serology, the 'window period' is defined as:", options:["Time between HBV exposure and symptom onset","Period when HBsAg has disappeared but anti-HBs has not yet appeared; only marker present is anti-HBc IgM","Time when HBeAg and anti-HBe are simultaneously positive","Period of maximum HBV DNA viraemia"], answer:1, explanation:"HBV window period: After HBsAg clears (neutralised) but before anti-HBs appears (immune response building), there is a 'serological gap'. During this period: HBsAg negative, anti-HBs negative, but anti-HBc IgM POSITIVE (the only detectable marker). Clinical significance: blood from a window period donor appears HBsAg-negative but is still infectious. Anti-HBc IgM differentiates window period from: vaccination (only anti-HBs positive), past infection/chronic (anti-HBc IgG + HBsAg or anti-HBs). 4th-generation HBV DNA NAT has minimised window period for blood screening." },
  { id:6103, subject:"Microbiology", stem:"HBsAg (hepatitis B surface antigen) positivity indicates:", options:["Immunity due to vaccination","Current infection (acute or chronic) with hepatitis B virus","Past resolved infection","Window period only"], answer:1, explanation:"HBsAg: the outer surface protein of HBV — appears 1-6 weeks after infection, BEFORE symptoms (incubation period). Its presence indicates CURRENT HBV INFECTION (acute or chronic). If HBsAg persists >6 months → chronic hepatitis B. HBsAg is the FIRST serological marker to appear. Vaccination produces only anti-HBs (no anti-HBc) — this distinguishes vaccinated from naturally immune individuals. Anti-HBs: protective antibody, appears after recovery or vaccination. HBeAg: marker of active viral replication and high infectivity. Anti-HBe: appearing as HBeAg clears (seroconversion) — lower replication." },
  { id:6104, subject:"Microbiology", stem:"Which hepatitis B marker indicates HIGH viral replication, HIGH infectivity, and is most strongly correlated with active liver damage?", options:["Anti-HBs","HBsAg alone","HBeAg (hepatitis B e antigen)","Anti-HBc IgG"], answer:2, explanation:"HBeAg: a soluble protein derived from processing of precore/core protein (not structural component of virion). Its presence correlates with: active viral replication, high HBV DNA levels, HIGH infectivity (risk of vertical and horizontal transmission), and ongoing liver damage. HBeAg seroconversion (HBeAg disappears, anti-HBe appears) marks a milestone — reduced replication, decreased infectivity, and often improvement in liver inflammation. Pre-core mutant HBV (HBeAg-negative chronic hepatitis B) produces HBV DNA without HBeAg production — particularly common in Mediterranean, Middle East, Asia." },
  { id:6105, subject:"Microbiology", stem:"HBV vaccination (recombinant HBsAg vaccine) induces immunity by producing which serological marker?", options:["Anti-HBc IgG","Anti-HBe","Anti-HBs (surface antibody — protective)","HBsAg"], answer:2, explanation:"HBV vaccine (recombinant HBsAg): stimulates production of ANTI-HBs ONLY (no anti-HBc, since the core antigen is not part of the vaccine). Anti-HBs >10 mIU/mL = protective immunity. This is the KEY distinguishing marker: Vaccination → anti-HBs only; Natural infection recovery → anti-HBs + anti-HBc IgG; Chronic infection → HBsAg + anti-HBc IgG (no anti-HBs). Non-responders to vaccine: check anti-HBs after 3-dose series — if <10 mIU/mL, re-vaccinate. Risk factors for non-response: obesity, smoking, immunosuppression, older age." },
  { id:6106, subject:"Microbiology", stem:"Plasmodium falciparum is the most virulent malaria parasite. Which characteristic gametocyte morphology distinguishes it from other Plasmodium species?", options:["Round gametocytes with Schüffner's dots","Banana/crescent-shaped (falciform) gametocytes","Oval gametocytes with fimbriated RBC","Large oval gametocytes filling the entire RBC"], answer:1, explanation:"P. falciparum gametocytes are BANANA/CRESCENT-SHAPED (falciform = sickle/crescent) — unique among malaria species. Other P. falciparum features: multiple ring forms (double chromatin dots) in ONE RBC, Maurer's clefts (irregular clefts in RBC cytoplasm), NO enlarged RBCs (RBCs normal or smaller size — rigid, causing sludging in capillaries → cerebral malaria), quartan fever (36-48 hours, irregular), sequestration of infected RBCs in cerebral capillaries via PfEMP1 (knobs). Diagnosis: thick film, RDT (HRP2 antigen). Treatment: ACT (artemether-lumefantrine)." },
  { id:6107, subject:"Microbiology", stem:"Plasmodium vivax malaria causes relapses weeks to months after apparent cure because of:", options:["Persistent blood-stage merozoites resistant to chloroquine","Dormant liver-stage forms (hypnozoites) that reactivate","Re-infection from mosquito bites during follow-up","Erythrocytic forms that sequester in the spleen"], answer:1, explanation:"P. vivax (and P. ovale) form HYPNOZOITES — dormant liver-stage forms that persist in hepatocytes for months to years after the primary infection is cleared. Hypnozoites are NOT killed by chloroquine (which only kills blood-stage parasites). PRIMAQUINE (8-aminoquinoline) is required for radical cure — kills hypnozoites and thus prevents relapse. Standard: chloroquine (blood stages) + primaquine 14 days (liver stages). Check G6PD status before primaquine (causes haemolytic anaemia in G6PD deficiency). Tafenoquine (single dose) is a newer alternative for radical cure." },
  { id:6108, subject:"Microbiology", stem:"Duffy antigen (DARC, Duffy Antigen Receptor for Chemokines) on RBCs is the receptor required for which malaria parasite to invade red blood cells?", options:["Plasmodium falciparum","Plasmodium vivax","Plasmodium malariae","Plasmodium knowlesi"], answer:1, explanation:"P. vivax merozoites use the Duffy binding protein (DBP/EBA-175) to bind the DARC (Duffy antigen receptor for chemokines) on RBCs for invasion. Individuals who are DUFFY ANTIGEN NEGATIVE (Fy⁻/Fy⁻ genotype — common in West Africans; ~70% of sub-Saharan Africans) are resistant to P. vivax malaria. This explains the relative absence of P. vivax in West Africa. P. falciparum uses different receptors (glycophorin A/B, GYPA) — not Duffy dependent — hence prevalent in Africa despite Duffy negativity. Sickle cell trait: protection against P. falciparum." },
  { id:6109, subject:"Microbiology", stem:"The HRP2 (histidine-rich protein 2) antigen detected by rapid diagnostic tests (RDTs) for malaria is specific for:", options:["All Plasmodium species","Plasmodium vivax only","Plasmodium falciparum","Plasmodium malariae and P. ovale"], answer:2, explanation:"HRP2 is a water-soluble antigen produced only by P. falciparum (and P. reichenowi — a primate parasite). Falciparum-specific RDTs detect HRP2 using lateral flow immunochromatography. Advantages: rapid (15-20 min), no microscopy needed, field-deployable. Limitation: HRP2 can persist for weeks after parasite clearance (false positive). HRP2 gene deletions in some P. falciparum strains (South America, Horn of Africa) → false negative. For non-falciparum malaria detection: pLDH (Plasmodium lactate dehydrogenase) RDTs detect all 4 species; aldolase-based RDTs also detect all species." },
  { id:6110, subject:"Microbiology", stem:"The HIV window period (between infection and positive antibody test) is approximately:", options:["1-3 days","3 weeks to 3 months (using 3rd generation antibody tests)","6-12 months","1-2 years"], answer:1, explanation:"HIV window period (serological): time between HIV infection and seroconversion (antibody detectable). With 3rd generation ELISA (antibody only): 3 weeks to 3 months (up to 90 days). With 4th generation combo tests (detects p24 antigen + antibodies): window reduced to 18-45 days (p24 antigen appears at 2-4 weeks). With RNA NAT (nucleic acid testing): window reduced to 9-11 days. Current UK guidelines use 4th generation tests: negative result at 45 days post-exposure = truly negative (no repeat needed unless ongoing risk). Importance: infectious during window period → HIV transmission risk." },
  { id:6111, subject:"Microbiology", stem:"As per NACO (National AIDS Control Organisation) 2021 guidelines, antiretroviral therapy (ART) should be initiated in HIV-positive patients:", options:["Only when CD4 count falls below 200 cells/mm³","Only when CD4 count falls below 350 cells/mm³","Regardless of CD4 count — in ALL HIV-positive patients (treat all)","Only in patients with WHO stage 3 or 4 disease"], answer:2, explanation:"NACO 2021 (and WHO 2015 'Treat All' policy): ART should be initiated in ALL HIV-positive individuals regardless of CD4 count or WHO clinical stage. Rationale: earlier ART prevents opportunistic infections, reduces transmission (Undetectable = Untransmittable: U=U), reduces inflammation and non-AIDS comorbidities. Preferred first-line ART in India (NACO 2021): TLE (Tenofovir + Lamivudine + Efavirenz as fixed-dose combination) OR DTG-based regimen (Tenofovir + Lamivudine + Dolutegravir — DTG preferred as 1st line now due to better tolerability and higher barrier to resistance)." },
  { id:6112, subject:"Microbiology", stem:"At which CD4 count threshold does Pneumocystis jirovecii pneumonia (PCP) typically occur in HIV patients?", options:["CD4 <500 cells/mm³","CD4 <350 cells/mm³","CD4 <200 cells/mm³","CD4 <50 cells/mm³"], answer:2, explanation:"PCP (Pneumocystis jirovecii pneumonia, previously P. carinii): typically occurs when CD4 <200 cells/mm³. Clinical: subacute onset dyspnoea, dry cough, bilateral interstitial infiltrates on CXR ('ground-glass' on CT), elevated LDH, low O2 saturation with exertion. Diagnosis: BAL + GMS or direct immunofluorescence (cannot be cultured). Treatment: high-dose co-trimoxazole (TMP-SMX) for 21 days; add prednisolone if PaO2 <70 mmHg. Prophylaxis: TMP-SMX when CD4 <200. PCP was the AIDS-defining illness that led to recognition of AIDS epidemic in 1981." },
  { id:6113, subject:"Microbiology", stem:"CMV (cytomegalovirus) retinitis and MAC (Mycobacterium avium complex) infection typically occur when HIV patient's CD4 count falls below:", options:["CD4 <200","CD4 <100","CD4 <50","CD4 <350"], answer:2, explanation:"Opportunistic infection thresholds in HIV: CD4 <200: PCP, histoplasmosis, coccidioidomycosis; CD4 <100: toxoplasmosis encephalitis, cryptosporidiosis, microsporidiosis; CD4 <50: CMV retinitis (floaters, visual loss → retinal detachment; treat: ganciclovir/valganciclovir), MAC disseminated infection (fever, night sweats, diarrhoea, hepatosplenomegaly, high bacteraemia; treat: azithromycin + ethambutol), cryptococcal meningitis (CD4 <100 usually). Prophylaxis: azithromycin 1200 mg weekly when CD4 <50 to prevent MAC; fluconazole for cryptococcal disease in high-prevalence areas." },
  { id:6114, subject:"Microbiology", stem:"Staphylococcus aureus MRSA (methicillin-resistant) is resistant to all beta-lactam antibiotics because of:", options:["Beta-lactamase enzyme production hydrolysing all penicillins","Acquisition of mecA gene encoding altered penicillin-binding protein PBP2a with low affinity for all beta-lactams","Reduced outer membrane permeability preventing drug entry","Efflux pump actively removing beta-lactams"], answer:1, explanation:"MRSA resistance mechanism: acquisition of mecA gene (on mobile genetic element SCCmec) encoding PBP2a (penicillin-binding protein 2a) — an altered transpeptidase with very low binding affinity for ALL beta-lactam antibiotics (penicillins, cephalosporins, carbapenems). Therefore ALL beta-lactams are ineffective against MRSA regardless of beta-lactamase production. Treatment: vancomycin (glycopeptide, IV), linezolid, daptomycin, ceftaroline (5th gen cephalosporin with activity against PBP2a), tedizolid. MRSA screening: chromogenic MRSA agar, PCR for mecA/mecC gene." },
  { id:6115, subject:"Microbiology", stem:"Which bacterial toxin mechanism causes 'rice-water' diarrhoea in cholera by activating adenylate cyclase?", options:["Pore-forming toxin destroying enterocyte membranes","A-B toxin: B subunit binds GM1 ganglioside on enterocytes; A1 subunit ADP-ribosylates Gs alpha protein → constitutive adenylate cyclase activation → massive cAMP → chloride secretion and water loss","Clostridial toxin cleaving SNARE proteins → ACh release failure","Shiga toxin inhibiting protein synthesis in enterocytes"], answer:1, explanation:"Cholera toxin (CT): classic A-B toxin. B pentamer binds GM1 ganglioside (on small intestinal enterocytes) irreversibly → A1 subunit enters cytoplasm → ADP-ribosylates Gs-alpha protein (permanently activates it) → constitutive activation of adenylate cyclase → massive cAMP production → PKA activation → phosphorylation of CFTR chloride channel → massive Cl⁻ secretion into gut lumen → osmotic water follows → profuse watery 'rice-water' diarrhoea (no blood, no pus). No mucosal invasion. Treatment: ORS + IV Ringer's lactate + doxycycline/azithromycin. Similar mechanism: E. coli LT toxin (labile toxin)." },
  { id:6116, subject:"Microbiology", stem:"Clostridium tetani produces tetanospasmin toxin. The mechanism causing spastic paralysis in tetanus is:", options:["Stimulation of alpha-motor neurons causing direct muscle contraction","Cleaves synaptobrevin (VAMP) at inhibitory interneurons in spinal cord → blocks release of glycine and GABA → unopposed motor neuron activity → spastic paralysis","Direct destruction of motor neurons in anterior horn","Competitive inhibition of acetylcholine at the neuromuscular junction"], answer:1, explanation:"Tetanospasmin (tetanus neurotoxin, TeNT): travels retrogradely along motor nerves to CNS. Cleaves synaptobrevin (VAMP) — a SNARE protein required for synaptic vesicle fusion — at INHIBITORY INTERNEURONS of spinal cord and brainstem → blocks release of GLYCINE and GABA (inhibitory neurotransmitters) → UNOPPOSED excitatory motor neuron activity → spastic paralysis, trismus (lockjaw), risus sardonicus (fixed grin), opisthotonos (arched back), autonomic instability. Botulinum toxin also cleaves SNAREs (SNAP-25, syntaxin) but at excitatory NMJ → FLACCID paralysis (opposite to tetanus)." },
  { id:6117, subject:"Microbiology", stem:"The Weil-Felix test (using Proteus agglutination) is used for serological diagnosis of:", options:["Typhoid fever","Rickettsial infections (e.g., scrub typhus, epidemic typhus, Rocky Mountain spotted fever)","Brucellosis","Leptospirosis"], answer:1, explanation:"Weil-Felix test: Rickettsia share antigens with certain Proteus species strains (OX-2, OX-19, OX-K) — cross-reactive polysaccharide antigens. Patient serum agglutinates these Proteus strains proportionally to rickettsial antibody titre. Results: Scrub typhus (Orientia tsutsugamushi): OX-K positive, OX-2 and OX-19 negative; Epidemic typhus (R. prowazekii): OX-2 and OX-19 positive; RMSF (R. rickettsii): OX-2 and OX-19 positive; Murine typhus (R. typhi): OX-19 positive. Weil-Felix has poor sensitivity and specificity — superseded by IFA (immunofluorescence) and PCR. Still used where specific tests unavailable." },
  { id:6118, subject:"Microbiology", stem:"The Rose-Bengal plate test (RBPT) is used as a screening test for:", options:["Typhoid (Salmonella typhi)","Brucellosis","Leptospirosis","Rickettsia"], answer:1, explanation:"Brucellosis diagnosis: (1) RBPT (Rose-Bengal plate test) — simple, rapid screening test using buffered B. abortus antigen at pH 3.65 + patient serum; agglutination = positive (very sensitive, may have false positives); (2) Serum agglutination test (SAT/Wright's agglutination) — titres ≥1:160 diagnostic; (3) Blood culture (gold standard — extended culture in Castañeda medium); (4) PCR; (5) ELISA. Brucella: gram-negative coccobacillus, intracellular (escapes killing in macrophages), transmitted from animals (cattle: B. abortus, goats/sheep: B. melitensis [most virulent], pigs: B. suis, dogs: B. canis) through unpasteurised dairy, meat contact, inhalation. Treatment: doxycycline 6 weeks + rifampicin or aminoglycoside." },
  { id:6119, subject:"Microbiology", stem:"Treponema pallidum (cause of syphilis) cannot be cultured in standard laboratory media. Laboratory diagnosis of primary syphilis (chancre) is best made by:", options:["Blood culture on chocolate agar","Dark-field microscopy of chancre exudate (visualises motile spirochaetes)","ZN stain of lesion swab","Gram stain of urethral discharge"], answer:1, explanation:"T. pallidum: very thin (0.1-0.2 μm wide) spirochaete — TOO THIN to be visualised by conventional light microscopy or Gram stain. DARK-FIELD MICROSCOPY: uses oblique illumination so that thin organisms scatter light and appear bright against dark background — ideal for visualising living, motile spirochaetes from primary chancre or condylomata lata. Cannot be grown in standard media (no in vitro culture). Serology: Non-treponemal tests (VDRL, RPR — screening, titres follow treatment response); Treponemal tests (TPHA, FTA-ABS — confirmatory, remain positive for life). Treponema pallidum particle agglutination (TPPA) — gold standard confirmation." },
  { id:6120, subject:"Microbiology", stem:"Koplik's spots, pathognomonic of measles, appear:", options:["On the skin of the trunk 2-3 days before the rash","On the buccal mucosa opposite the lower molars, 2-3 days BEFORE the skin rash appears","In the throat at the time of maximum rash","On the palate simultaneously with the petechial rash of rubella"], answer:1, explanation:"Koplik's spots: small white/bluish-white spots on an erythematous background on the BUCCAL MUCOSA (inner cheek) opposite the lower molars — pathognomonic of measles (rubeola, paramyxovirus). They appear 1-2 days BEFORE the maculopapular skin rash (which starts on face, spreads cephalocaudally) and disappear as rash appears. Their recognition allows early (pre-rash) diagnosis. Measles: 4 C's — Cough, Coryza, Conjunctivitis, Koplik's spots — followed by rash. Complications: pneumonia (most common cause of death), encephalitis, SSPE (subacute sclerosing panencephalitis — late, due to defective measles persistence). MMR vaccine prevents measles." },
];
